     1→# Code Patterns - MMS
     2→
     3→> Consolidated from EXTRACT-CODE-001.jsonl (working patterns) and EXTRACT-CODE-002.jsonl (anti-patterns)
     4→
     5→---
     6→
     7→## Working Code Patterns
     8→
     9→### 1. SimulationStore - Structure of Arrays (SoA) with TypedArrays
    10→
    11→**File:** `src/engine/stores/SimulationStore.ts`
    12→
    13→Complete SoA store using TypedArrays for high-performance scheduling data with Zustand.
    14→
    15→```typescript
    16→/**
    17→ * SimulationStore - Structure of Arrays (SoA) Implementation
    18→ *
    19→ * This store manages schedule block data using TypedArrays for optimal
    20→ * cache performance and minimal GC pressure. All bulk operations work
    21→ * directly on contiguous memory.
    22→ *
    23→ * Architecture Decision: We use SoA instead of AoS (Array of Structures)
    24→ * because timeline operations typically iterate over single properties
    25→ * (e.g., all start times for collision detection) rather than all
    26→ * properties of single blocks.
    27→ */
    28→
    29→import { create } from 'zustand';
    30→import { subscribeWithSelector } from 'zustand/middleware';
    31→import { IntervalTree } from '../core/IntervalTree';
    32→import type { BlockType, BlockStatus, ScheduleBlockInput } from '../types';
    33→
    34→/** Initial capacity - will grow dynamically */
    35→const INITIAL_CAPACITY = 1024;
    36→
    37→/** Growth factor when resizing arrays */
    38→const GROWTH_FACTOR = 2;
    39→
    40→/** Block type to numeric index mapping for TypedArray storage */
    41→const BLOCK_TYPE_INDEX: Record<BlockType, number> = {
    42→  A_CHECK: 0,
    43→  B_CHECK: 1,
    44→  C_CHECK: 2,
    45→  D_CHECK: 3,
    46→  ENGINE_OVERHAUL: 4,
    47→  LANDING_GEAR: 5,
    48→  APU_SERVICE: 6,
    49→  INTERIOR_REFURB: 7,
    50→  PAINT: 8,
    51→  MOD_UPGRADE: 9,
    52→  AOG_REPAIR: 10,
    53→  LEASE_RETURN: 11,
    54→  CUSTOM: 12,
    55→};
    56→
    57→/** Reverse mapping for retrieving block type from index */
    58→const INDEX_TO_BLOCK_TYPE: BlockType[] = [
    59→  'A_CHECK',
    60→  'B_CHECK',
    61→  'C_CHECK',
    62→  'D_CHECK',
    63→  'ENGINE_OVERHAUL',
    64→  'LANDING_GEAR',
    65→  'APU_SERVICE',
    66→  'INTERIOR_REFURB',
    67→  'PAINT',
    68→  'MOD_UPGRADE',
    69→  'AOG_REPAIR',
    70→  'LEASE_RETURN',
    71→  'CUSTOM',
    72→];
    73→
    74→/**
    75→ * Structure of Arrays data container
    76→ * Each array index corresponds to the same block entity
    77→ */
    78→interface SoAData {
    79→  /** Block start timestamps in milliseconds */
    80→  startMs: Float64Array;
    81→  /** Block durations in milliseconds */
    82→  durationMs: Float64Array;
    83→  /** Aircraft row indices */
    84→  aircraftIndex: Uint16Array;
    85→  /** Block type indices (see BLOCK_TYPE_INDEX) */
    86→  typeIndex: Uint8Array;
    87→  /** Block status (0=scheduled, 1=in-progress, 2=completed, 3=cancelled) */
    88→  status: Uint8Array;
    89→  /** Unique block IDs for external reference */
    90→  ids: Uint32Array;
    91→}
    92→
    93→interface SimulationState {
    94→  /** SoA data arrays */
    95→  data: SoAData;
    96→  /** Current number of blocks */
    97→  count: number;
    98→  /** Current array capacity */
    99→  capacity: number;
   100→  /** Next available block ID */
   101→  nextId: number;
   102→  /** Interval tree for efficient range queries */
   103→  intervalTree: IntervalTree;
   104→  /** Currently selected block ID (null if none) */
   105→  selectedBlockId: number | null;
   106→  /** Viewport time range for visible blocks */
   107→  viewportStart: number;
   108→  viewportEnd: number;
   109→}
   110→
   111→interface SimulationActions {
   112→  /** Add a new schedule block, returns the assigned ID */
   113→  addBlock: (block: ScheduleBlockInput) => number;
   114→  /** Update an existing block's properties */
   115→  updateBlock: (id: number, updates: Partial<ScheduleBlockInput>) => void;
   116→  /** Remove a block by ID */
   117→  removeBlock: (id: number) => void;
   118→  /** Query blocks within a time range */
   119→  queryRange: (startMs: number, endMs: number) => number[];
   120→  /** Set the currently selected block */
   121→  selectBlock: (id: number | null) => void;
   122→  /** Update viewport bounds for virtualization */
   123→  setViewport: (startMs: number, endMs: number) => void;
   124→  /** Get block data by ID */
   125→  getBlock: (id: number) => {
   126→    id: number;
   127→    startMs: number;
   128→    durationMs: number;
   129→    aircraftIndex: number;
   130→    type: BlockType;
   131→    status: BlockStatus;
   132→  } | null;
   133→  /** Bulk load blocks (replaces existing data) */
   134→  loadBlocks: (blocks: ScheduleBlockInput[]) => void;
   135→  /** Clear all blocks */
   136→  clear: () => void;
   137→}
   138→
   139→type SimulationStore = SimulationState & SimulationActions;
   140→
   141→/**
   142→ * Create initial SoA data structure with given capacity
   143→ */
   144→function createSoAData(capacity: number): SoAData {
   145→  return {
   146→    startMs: new Float64Array(capacity),
   147→    durationMs: new Float64Array(capacity),
   148→    aircraftIndex: new Uint16Array(capacity),
   149→    typeIndex: new Uint8Array(capacity),
   150→    status: new Uint8Array(capacity),
   151→    ids: new Uint32Array(capacity),
   152→  };
   153→}
   154→
   155→/**
   156→ * Resize SoA arrays to new capacity, preserving existing data
   157→ */
   158→function resizeSoAData(data: SoAData, oldCount: number, newCapacity: number): SoAData {
   159→  const newData = createSoAData(newCapacity);
   160→
   161→  // Copy existing data
   162→  newData.startMs.set(data.startMs.subarray(0, oldCount));
   163→  newData.durationMs.set(data.durationMs.subarray(0, oldCount));
   164→  newData.aircraftIndex.set(data.aircraftIndex.subarray(0, oldCount));
   165→  newData.typeIndex.set(data.typeIndex.subarray(0, oldCount));
   166→  newData.status.set(data.status.subarray(0, oldCount));
   167→  newData.ids.set(data.ids.subarray(0, oldCount));
   168→
   169→  return newData;
   170→}
   171→
   172→/**
   173→ * Convert BlockStatus to numeric value
   174→ */
   175→function statusToNumber(status: BlockStatus): number {
   176→  switch (status) {
   177→    case 'scheduled':
   178→      return 0;
   179→    case 'in-progress':
   180→      return 1;
   181→    case 'completed':
   182→      return 2;
   183→    case 'cancelled':
   184→      return 3;
   185→    default:
   186→      return 0;
   187→  }
   188→}
   189→
   190→/**
   191→ * Convert numeric value to BlockStatus
   192→ */
   193→function numberToStatus(num: number): BlockStatus {
   194→  switch (num) {
   195→    case 0:
   196→      return 'scheduled';
   197→    case 1:
   198→      return 'in-progress';
   199→    case 2:
   200→      return 'completed';
   201→    case 3:
   202→      return 'cancelled';
   203→    default:
   204→      return 'scheduled';
   205→  }
   206→}
   207→
   208→/**
   209→ * Main simulation store using Zustand with SoA architecture
   210→ */
   211→export const useSimulationStore = create<SimulationStore>()(
   212→  subscribeWithSelector((set, get) => ({
   213→    // Initial state
   214→    data: createSoAData(INITIAL_CAPACITY),
   215→    count: 0,
   216→    capacity: INITIAL_CAPACITY,
   217→    nextId: 1,
   218→    intervalTree: new IntervalTree(),
   219→    selectedBlockId: null,
   220→    viewportStart: 0,
   221→    viewportEnd: Date.now() + 365 * 24 * 60 * 60 * 1000, // 1 year default
   222→
   223→    addBlock: (block: ScheduleBlockInput): number => {
   224→      const state = get();
   225→      let { data, count, capacity, nextId, intervalTree } = state;
   226→
   227→      // Grow arrays if needed
   228→      if (count >= capacity) {
   229→        const newCapacity = capacity * GROWTH_FACTOR;
   230→        data = resizeSoAData(data, count, newCapacity);
   231→        capacity = newCapacity;
   232→      }
   233→
   234→      // Assign ID and store block data
   235→      const id = nextId;
   236→      const index = count;
   237→
   238→      data.ids[index] = id;
   239→      data.startMs[index] = block.startMs;
   240→      data.durationMs[index] = block.durationMs;
   241→      data.aircraftIndex[index] = block.aircraftIndex;
   242→      data.typeIndex[index] = BLOCK_TYPE_INDEX[block.type];
   243→      data.status[index] = statusToNumber(block.status ?? 'scheduled');
   244→
   245→      // Add to interval tree for range queries
   246→      intervalTree.insert(block.startMs, block.startMs + block.durationMs, id);
   247→
   248→      set({
   249→        data,
   250→        count: count + 1,
   251→        capacity,
   252→        nextId: nextId + 1,
   253→        intervalTree,
   254→      });
   255→
   256→      return id;
   257→    },
   258→
   259→    updateBlock: (id: number, updates: Partial<ScheduleBlockInput>): void => {
   260→      const state = get();
   261→      const { data, count, intervalTree } = state;
   262→
   263→      // Find block index by ID
   264→      let index = -1;
   265→      for (let i = 0; i < count; i++) {
   266→        if (data.ids[i] === id) {
   267→          index = i;
   268→          break;
   269→        }
   270→      }
   271→
   272→      if (index === -1) return;
   273→
   274→      // Get old values for interval tree update
   275→      const oldStart = data.startMs[index];
   276→      const oldEnd = oldStart + data.durationMs[index];
   277→
   278→      // Apply updates
   279→      if (updates.startMs !== undefined) {
   280→        data.startMs[index] = updates.startMs;
   281→      }
   282→      if (updates.durationMs !== undefined) {
   283→        data.durationMs[index] = updates.durationMs;
   284→      }
   285→      if (updates.aircraftIndex !== undefined) {
   286→        data.aircraftIndex[index] = updates.aircraftIndex;
   287→      }
   288→      if (updates.type !== undefined) {
   289→        data.typeIndex[index] = BLOCK_TYPE_INDEX[updates.type];
   290→      }
   291→      if (updates.status !== undefined) {
   292→        data.status[index] = statusToNumber(updates.status);
   293→      }
   294→
   295→      // Update interval tree if time changed
   296→      if (updates.startMs !== undefined || updates.durationMs !== undefined) {
   297→        intervalTree.remove(oldStart, oldEnd, id);
   298→        const newStart = data.startMs[index];
   299→        const newEnd = newStart + data.durationMs[index];
   300→        intervalTree.insert(newStart, newEnd, id);
   301→      }
   302→
   303→      set({ data, intervalTree });
   304→    },
   305→
   306→    removeBlock: (id: number): void => {
   307→      const state = get();
   308→      const { data, intervalTree } = state;
   309→      let { count } = state;
   310→
   311→      // Find block index by ID
   312→      let index = -1;
   313→      for (let i = 0; i < count; i++) {
   314→        if (data.ids[i] === id) {
   315→          index = i;
   316→          break;
   317→        }
   318→      }
   319→
   320→      if (index === -1) return;
   321→
   322→      // Remove from interval tree
   323→      const start = data.startMs[index];
   324→      const end = start + data.durationMs[index];
   325→      intervalTree.remove(start, end, id);
   326→
   327→      // Swap with last element and decrement count (avoids shifting)
   328→      const lastIndex = count - 1;
   329→      if (index !== lastIndex) {
   330→        data.ids[index] = data.ids[lastIndex];
   331→        data.startMs[index] = data.startMs[lastIndex];
   332→        data.durationMs[index] = data.durationMs[lastIndex];
   333→        data.aircraftIndex[index] = data.aircraftIndex[lastIndex];
   334→        data.typeIndex[index] = data.typeIndex[lastIndex];
   335→        data.status[index] = data.status[lastIndex];
   336→      }
   337→
   338→      set({ data, count: count - 1, intervalTree });
   339→    },
   340→
   341→    queryRange: (startMs: number, endMs: number): number[] => {
   342→      const { intervalTree } = get();
   343→      return intervalTree.query(startMs, endMs);
   344→    },
   345→
   346→    selectBlock: (id: number | null): void => {
   347→      set({ selectedBlockId: id });
   348→    },
   349→
   350→    setViewport: (startMs: number, endMs: number): void => {
   351→      set({ viewportStart: startMs, viewportEnd: endMs });
   352→    },
   353→
   354→    getBlock: (id: number) => {
   355→      const { data, count } = get();
   356→
   357→      // Find block index by ID
   358→      for (let i = 0; i < count; i++) {
   359→        if (data.ids[i] === id) {
   360→          return {
   361→            id,
   362→            startMs: data.startMs[i],
   363→            durationMs: data.durationMs[i],
   364→            aircraftIndex: data.aircraftIndex[i],
   365→            type: INDEX_TO_BLOCK_TYPE[data.typeIndex[i]],
   366→            status: numberToStatus(data.status[i]),
   367→          };
   368→        }
   369→      }
   370→
   371→      return null;
   372→    },
   373→
   374→    loadBlocks: (blocks: ScheduleBlockInput[]): void => {
   375→      const requiredCapacity = Math.max(INITIAL_CAPACITY, blocks.length);
   376→      const data = createSoAData(requiredCapacity);
   377→      const intervalTree = new IntervalTree();
   378→
   379→      let nextId = 1;
   380→      for (let i = 0; i < blocks.length; i++) {
   381→        const block = blocks[i];
   382→        data.ids[i] = nextId;
   383→        data.startMs[i] = block.startMs;
   384→        data.durationMs[i] = block.durationMs;
   385→        data.aircraftIndex[i] = block.aircraftIndex;
   386→        data.typeIndex[i] = BLOCK_TYPE_INDEX[block.type];
   387→        data.status[i] = statusToNumber(block.status ?? 'scheduled');
   388→
   389→        intervalTree.insert(block.startMs, block.startMs + block.durationMs, nextId);
   390→        nextId++;
   391→      }
   392→
   393→      set({
   394→        data,
   395→        count: blocks.length,
   396→        capacity: requiredCapacity,
   397→        nextId,
   398→        intervalTree,
   399→        selectedBlockId: null,
   400→      });
   401→    },
   402→
   403→    clear: (): void => {
   404→      set({
   405→        data: createSoAData(INITIAL_CAPACITY),
   406→        count: 0,
   407→        capacity: INITIAL_CAPACITY,
   408→        nextId: 1,
   409→        intervalTree: new IntervalTree(),
   410→        selectedBlockId: null,
   411→      });
   412→    },
   413→  }))
   414→);
   415→
   416→/**
   417→ * Selector for getting visible blocks based on current viewport
   418→ */
   419→export const selectVisibleBlocks = (state: SimulationStore): number[] => {
   420→  return state.queryRange(state.viewportStart, state.viewportEnd);
   421→};
   422→
   423→/**
   424→ * Selector for getting blocks by aircraft index
   425→ */
   426→export const selectBlocksByAircraft = (
   427→  state: SimulationStore,
   428→  aircraftIndex: number
   429→): number[] => {
   430→  const { data, count } = state;
   431→  const result: number[] = [];
   432→
   433→  for (let i = 0; i < count; i++) {
   434→    if (data.aircraftIndex[i] === aircraftIndex) {
   435→      result.push(data.ids[i]);
   436→    }
   437→  }
   438→
   439→  return result;
   440→};
   441→```
