   444→
   445→### 2. MacroLayer - Heatmap View (Zoom < 0.5x)
   446→
   447→**File:** `apps/canvas/src/deck/layers/MacroLayer.ts`
   448→
   449→deck.gl SolidPolygonLayer for aggregated task density heatmap with d3-scale-chromatic color interpolation.
   450→
   451→```typescript
   452→/**
   453→ * MacroLayer - Heatmap view for zoom < 0.5x
   454→ * Uses SolidPolygonLayer to render aggregated task density cells
   455→ */
   456→import { SolidPolygonLayer } from '@deck.gl/layers';
   457→import { interpolateYlOrRd } from 'd3-scale-chromatic';
   458→import type { TaskRender, Train } from '../../data/types';
   459→import { DEFAULT_VIEW_CONFIG } from '../../data/types';
   460→
   461→const DAYS_PER_CELL = 30; // ~1 month per cell
   462→const { pxPerDay, pxPerTrain } = DEFAULT_VIEW_CONFIG;
   463→const CELL_WIDTH = DAYS_PER_CELL * pxPerDay; // 300px
   464→const CELL_HEIGHT = pxPerTrain; // 24px
   465→
   466→interface HeatmapCell {
   467→  polygon: number[][];
   468→  color: [number, number, number, number];
   469→  taskCount: number;
   470→}
   471→
   472→interface YearMarker {
   473→  polygon: number[][];
   474→  color: [number, number, number, number];
   475→}
   476→
   477→function parseColorToRGBA(cssColor: string, alpha = 255): [number, number, number, number] {
   478→  // Parse rgb(r, g, b) or rgba(r, g, b, a) format from d3-scale-chromatic
   479→  const match = cssColor.match(/rgba?\((\d+),\s*(\d+),\s*(\d+)(?:,\s*([\d.]+))?\)/);
   480→  if (match) {
   481→    return [
   482→      parseInt(match[1]),
   483→      parseInt(match[2]),
   484→      parseInt(match[3]),
   485→      match[4] ? Math.round(parseFloat(match[4]) * 255) : alpha
   486→    ];
   487→  }
   488→  return [128, 128, 128, alpha];
   489→}
   490→
   491→export interface MacroLayerOptions {
   492→  tasks: TaskRender[];
   493→  trains: Train[];
   494→  opacity: number;
   495→  totalDays: number;
   496→}
   497→
   498→export function createMacroLayers({
   499→  tasks,
   500→  trains,
   501→  opacity,
   502→  totalDays
   503→}: MacroLayerOptions): SolidPolygonLayer[] {
   504→  if (opacity <= 0) return [];
   505→
   506→  // Aggregate tasks into grid cells
   507→  const numCols = Math.ceil(totalDays / DAYS_PER_CELL);
   508→  const numRows = trains.length;
   509→  const cellCounts: number[][] = Array.from({ length: numRows }, () =>
   510→    Array(numCols).fill(0)
   511→  );
   512→
   513→  // Count tasks per cell
   514→  for (const task of tasks) {
   515→    const row = task.trainIndex;
   516→    const startCol = Math.floor(task.startDay / DAYS_PER_CELL);
   517→    const endCol = Math.floor((task.startDay + task.duration) / DAYS_PER_CELL);
   518→    for (let col = startCol; col <= endCol && col < numCols; col++) {
   519→      if (col >= 0 && row >= 0 && row < numRows) {
   520→        cellCounts[row][col]++;
   521→      }
   522→    }
   523→  }
   524→
   525→  // Find max for normalization
   526→  let maxCount = 1;
   527→  for (const row of cellCounts) {
   528→    for (const count of row) {
   529→      if (count > maxCount) maxCount = count;
   530→    }
   531→  }
   532→
   533→  // Create heatmap cells
   534→  const cells: HeatmapCell[] = [];
   535→  for (let row = 0; row < numRows; row++) {
   536→    for (let col = 0; col < numCols; col++) {
   537→      const count = cellCounts[row][col];
   538→      if (count === 0) continue;
   539→
   540→      const x = col * CELL_WIDTH;
   541→      const y = -row * CELL_HEIGHT; // Negative Y for downward trains
   542→      const normalized = count / maxCount;
   543→      const cssColor = interpolateYlOrRd(normalized);
   544→      const color = parseColorToRGBA(cssColor, Math.round(opacity * 255));
   545→
   546→      cells.push({
   547→        polygon: [
   548→          [x, y],
   549→          [x + CELL_WIDTH, y],
   550→          [x + CELL_WIDTH, y - CELL_HEIGHT],
   551→          [x, y - CELL_HEIGHT],
   552→          [x, y]
   553→        ],
   554→        color,
   555→        taskCount: count
   556→      });
   557→    }
   558→  }
   559→
   560→  // Year markers (vertical lines)
   561→  const yearMarkers: YearMarker[] = [];
   562→  for (let day = 365; day < totalDays; day += 365) {
   563→    const x = day * pxPerDay;
   564→    yearMarkers.push({
   565→      polygon: [
   566→        [x - 1, 0],
   567→        [x + 1, 0],
   568→        [x + 1, -numRows * CELL_HEIGHT],
   569→        [x - 1, -numRows * CELL_HEIGHT],
   570→        [x - 1, 0]
   571→      ],
   572→      color: [100, 100, 100, Math.round(opacity * 128)]
   573→    });
   574→  }
   575→
   576→  return [
   577→    new SolidPolygonLayer<HeatmapCell>({
   578→      id: 'macro-heatmap',
   579→      data: cells,
   580→      getPolygon: d => d.polygon,
   581→      getFillColor: d => d.color,
   582→      extruded: false,
   583→      pickable: false
   584→    }),
   585→    new SolidPolygonLayer<YearMarker>({
   586→      id: 'macro-year-markers',
   587→      data: yearMarkers,
   588→      getPolygon: d => d.polygon,
   589→      getFillColor: d => d.color,
   590→      extruded: false,
   591→      pickable: false
   592→    })
   593→  ];
   594→}
   595→```
