   599→### 3. MesoLayer - Task Blocks View (0.5x <= Zoom <= 2.0x)
   600→
   601→**File:** `apps/canvas/src/deck/layers/MesoLayer.ts`
   602→
   603→Multiple SolidPolygonLayer stacks for backgrounds, conflicts, focus, and task blocks with hover highlighting.
   604→
   605→```typescript
   606→/**
   607→ * MesoLayer - Task blocks view for 0.5x <= zoom <= 2.0x
   608→ * Uses multiple SolidPolygonLayer stacks for backgrounds, conflicts, focus, and task blocks
   609→ */
   610→import { SolidPolygonLayer } from '@deck.gl/layers';
   611→import type { TaskRender, Train } from '../../data/types';
   612→import { DEFAULT_VIEW_CONFIG } from '../../data/types';
   613→
   614→const { pxPerDay, pxPerTrain } = DEFAULT_VIEW_CONFIG;
   615→const TASK_HEIGHT = pxPerTrain - 4; // 20px with 2px padding
   616→const TASK_PADDING = 2;
   617→
   618→interface RowBackground {
   619→  polygon: number[][];
   620→  color: [number, number, number, number];
   621→}
   622→
   623→interface TaskPolygon {
   624→  id: string;
   625→  polygon: number[][];
   626→  color: [number, number, number, number];
   627→  task: TaskRender;
   628→}
   629→
   630→interface EffectPolygon {
   631→  polygon: number[][];
   632→  color: [number, number, number, number];
   633→}
   634→
   635→const COLORS = {
   636→  blue: [59, 130, 246, 255] as [number, number, number, number],
   637→  orange: [245, 158, 11, 255] as [number, number, number, number],
   638→  gray: [156, 163, 175, 255] as [number, number, number, number],
   639→};
   640→
   641→const CONFLICT_COLOR: [number, number, number, number] = [239, 68, 68, 76]; // red @ 30% opacity
   642→const FOCUS_COLOR: [number, number, number, number] = [139, 92, 246, 102]; // violet @ 40% opacity
   643→const HOVER_BRIGHTEN = 1.5;
   644→
   645→function getTaskColor(task: TaskRender, isHovered: boolean): [number, number, number, number] {
   646→  let baseColor: [number, number, number, number];
   647→  switch (task.color) {
   648→    case 'blue': baseColor = [...COLORS.blue]; break;
   649→    case 'orange': baseColor = [...COLORS.orange]; break;
   650→    default: baseColor = [...COLORS.gray];
   651→  }
   652→
   653→  if (isHovered) {
   654→    baseColor[0] = Math.min(255, Math.round(baseColor[0] * HOVER_BRIGHTEN));
   655→    baseColor[1] = Math.min(255, Math.round(baseColor[1] * HOVER_BRIGHTEN));
   656→    baseColor[2] = Math.min(255, Math.round(baseColor[2] * HOVER_BRIGHTEN));
   657→  }
   658→
   659→  return baseColor;
   660→}
   661→
   662→function createRectPolygon(x: number, y: number, w: number, h: number): number[][] {
   663→  return [
   664→    [x, y],
   665→    [x + w, y],
   666→    [x + w, y - h],
   667→    [x, y - h],
   668→    [x, y]
   669→  ];
   670→}
   671→
   672→export interface MesoLayerOptions {
   673→  tasks: TaskRender[];
   674→  trains: Train[];
   675→  opacity: number;
   676→  totalDays: number;
   677→  hoveredTaskId?: string | null;
   678→  selectedTaskId?: string | null;
   679→  focusedTaskId?: string | null;
   680→  viewportBounds?: { minX: number; maxX: number; minY: number; maxY: number };
   681→}
   682→
   683→export function createMesoLayers({
   684→  tasks,
   685→  trains,
   686→  opacity,
   687→  totalDays,
   688→  hoveredTaskId,
   689→  selectedTaskId,
   690→  focusedTaskId,
   691→  viewportBounds
   692→}: MesoLayerOptions): SolidPolygonLayer[] {
   693→  if (opacity <= 0) return [];
   694→
   695→  // Row backgrounds (alternating colors)
   696→  const rowBackgrounds: RowBackground[] = trains.map((_, index) => ({
   697→    polygon: createRectPolygon(0, -index * pxPerTrain, totalDays * pxPerDay, pxPerTrain),
   698→    color: index % 2 === 0
   699→      ? [255, 255, 255, Math.round(opacity * 255)]
   700→      : [248, 250, 252, Math.round(opacity * 255)] // slate-50
   701→  }));
   702→
   703→  // Filter visible tasks if viewport bounds provided
   704→  const visibleTasks = viewportBounds
   705→    ? tasks.filter(task => {
   706→        const x1 = task.startDay * pxPerDay;
   707→        const x2 = x1 + task.duration * pxPerDay;
   708→        const y = -task.trainIndex * pxPerTrain;
   709→        return x2 >= viewportBounds.minX &&
   710→               x1 <= viewportBounds.maxX &&
   711→               y >= viewportBounds.minY &&
   712→               y - pxPerTrain <= viewportBounds.maxY;
   713→      })
   714→    : tasks;
   715→
   716→  // Conflict glows
   717→  const conflictGlows: EffectPolygon[] = visibleTasks
   718→    .filter(task => task.hasConflict)
   719→    .map(task => ({
   720→      polygon: createRectPolygon(
   721→        task.startDay * pxPerDay - 4,
   722→        -task.trainIndex * pxPerTrain - TASK_PADDING + 4,
   723→        task.duration * pxPerDay + 8,
   724→        TASK_HEIGHT + 8
   725→      ),
   726→      color: [CONFLICT_COLOR[0], CONFLICT_COLOR[1], CONFLICT_COLOR[2], Math.round(CONFLICT_COLOR[3] * opacity)]
   727→    }));
   728→
   729→  // Focus ring
   730→  const focusRings: EffectPolygon[] = focusedTaskId
   731→    ? visibleTasks
   732→        .filter(task => task.id === focusedTaskId)
   733→        .map(task => ({
   734→          polygon: createRectPolygon(
   735→            task.startDay * pxPerDay - 4,
   736→            -task.trainIndex * pxPerTrain - TASK_PADDING + 4,
   737→            task.duration * pxPerDay + 8,
   738→            TASK_HEIGHT + 8
   739→          ),
   740→          color: [FOCUS_COLOR[0], FOCUS_COLOR[1], FOCUS_COLOR[2], Math.round(FOCUS_COLOR[3] * opacity)]
   741→        }))
   742→    : [];
   743→
   744→  // Task blocks
   745→  const taskPolygons: TaskPolygon[] = visibleTasks.map(task => ({
   746→    id: task.id,
   747→    polygon: createRectPolygon(
   748→      task.startDay * pxPerDay,
   749→      -task.trainIndex * pxPerTrain - TASK_PADDING,
   750→      task.duration * pxPerDay,
   751→      TASK_HEIGHT
   752→    ),
   753→    color: getTaskColor(task, task.id === hoveredTaskId),
   754→    task
   755→  }));
   756→
   757→  const layers: SolidPolygonLayer[] = [];
   758→
   759→  layers.push(
   760→    new SolidPolygonLayer<RowBackground>({
   761→      id: 'meso-row-backgrounds',
   762→      data: rowBackgrounds,
   763→      getPolygon: d => d.polygon,
   764→      getFillColor: d => d.color,
   765→      extruded: false,
   766→      pickable: false
   767→    })
   768→  );
   769→
   770→  if (conflictGlows.length > 0) {
   771→    layers.push(
   772→      new SolidPolygonLayer<EffectPolygon>({
   773→        id: 'meso-conflict-glows',
   774→        data: conflictGlows,
   775→        getPolygon: d => d.polygon,
   776→        getFillColor: d => d.color,
   777→        extruded: false,
   778→        pickable: false
   779→      })
   780→    );
   781→  }
   782→
   783→  if (focusRings.length > 0) {
   784→    layers.push(
   785→      new SolidPolygonLayer<EffectPolygon>({
   786→        id: 'meso-focus-rings',
   787→        data: focusRings,
   788→        getPolygon: d => d.polygon,
   789→        getFillColor: d => d.color,
   790→        extruded: false,
   791→        pickable: false
   792→      })
   793→    );
   794→  }
   795→
   796→  layers.push(
   797→    new SolidPolygonLayer<TaskPolygon>({
   798→      id: 'meso-task-blocks',
   799→      data: taskPolygons,
   800→      getPolygon: d => d.polygon,
   801→      getFillColor: d => d.color,
   802→      extruded: false,
   803→      pickable: true,
   804→      updateTriggers: {
   805→        getFillColor: [hoveredTaskId, opacity]
   806→      }
   807→    })
   808→  );
   809→
   810→  return layers;
   811→}
   812→```
