   870→  gray: [156, 163, 175, 255] as [number, number, number, number],
   871→};
   872→
   873→const SELECTION_COLOR: [number, number, number, number] = [6, 182, 212, 255]; // cyan-500
   874→const CONFLICT_COLOR: [number, number, number, number] = [239, 68, 68, 76];
   875→const FOCUS_COLOR: [number, number, number, number] = [139, 92, 246, 102];
   876→const DEPENDENCY_COLOR: [number, number, number, number] = [100, 116, 139, 255]; // slate-500
   877→
   878→function createRectPolygon(x: number, y: number, w: number, h: number): number[][] {
   879→  return [[x, y], [x + w, y], [x + w, y - h], [x, y - h], [x, y]];
   880→}
   881→
   882→function getTaskColor(task: TaskRender, isHovered: boolean, isSelected: boolean): [number, number, number, number] {
   883→  if (isSelected) return SELECTION_COLOR;
   884→
   885→  let baseColor: [number, number, number, number];
   886→  switch (task.color) {
   887→    case 'blue': baseColor = [...COLORS.blue]; break;
   888→    case 'orange': baseColor = [...COLORS.orange]; break;
   889→    default: baseColor = [...COLORS.gray];
   890→  }
   891→
   892→  if (isHovered) {
   893→    baseColor[0] = Math.min(255, Math.round(baseColor[0] * 1.3));
   894→    baseColor[1] = Math.min(255, Math.round(baseColor[1] * 1.3));
   895→    baseColor[2] = Math.min(255, Math.round(baseColor[2] * 1.3));
   896→  }
   897→
   898→  return baseColor;
   899→}
   900→
   901→function filterVisibleTasks(
   902→  tasks: TaskRender[],
   903→  bounds: { minX: number; maxX: number; minY: number; maxY: number },
   904→  overscan = 200
   905→): TaskRender[] {
   906→  return tasks.filter(task => {
   907→    const x1 = task.startDay * pxPerDay;
   908→    const x2 = x1 + task.duration * pxPerDay;
   909→    const y = -task.trainIndex * pxPerTrain;
   910→    return x2 >= bounds.minX - overscan &&
   911→           x1 <= bounds.maxX + overscan &&
   912→           y >= bounds.minY - overscan &&
   913→           y - pxPerTrain <= bounds.maxY + overscan;
   914→  });
   915→}
   916→
   917→function createDependencyPath(
   918→  from: TaskRender,
   919→  to: TaskRender,
   920→  allTasks: Map<string, TaskRender>
   921→): [number, number][] {
   922→  const fromX = (from.startDay + from.duration) * pxPerDay;
   923→  const fromY = -from.trainIndex * pxPerTrain - pxPerTrain / 2;
   924→  const toX = to.startDay * pxPerDay;
   925→  const toY = -to.trainIndex * pxPerTrain - pxPerTrain / 2;
   926→
   927→  const midX = (fromX + toX) / 2;
   928→
   929→  if (from.trainIndex === to.trainIndex) {
   930→    // Same row: simple curve
   931→    return [
   932→      [fromX, fromY],
   933→      [midX, fromY - 10],
   934→      [toX, toY]
   935→    ];
   936→  } else {
   937→    // Different rows: S-curve
   938→    return [
   939→      [fromX, fromY],
   940→      [fromX + 20, fromY],
   941→      [toX - 20, toY],
   942→      [toX, toY]
   943→    ];
   944→  }
   945→}
