   957→
   958→export function createMicroLayers(options: MicroLayerOptions): (SolidPolygonLayer | TextLayer | PathLayer)[] {
   959→  const {
   960→    tasks,
   961→    trains,
   962→    opacity,
   963→    totalDays,
   964→    hoveredTaskId,
   965→    selectedTaskId,
   966→    focusedTaskId,
   967→    viewportBounds
   968→  } = options;
   969→
   970→  if (opacity <= 0) return [];
   971→
   972→  const layers: (SolidPolygonLayer | TextLayer | PathLayer)[] = [];
   973→
   974→  // 1. Row backgrounds
   975→  const rowBackgrounds: RowBackground[] = trains.map((_, index) => ({
   976→    polygon: createRectPolygon(0, -index * pxPerTrain, totalDays * pxPerDay, pxPerTrain),
   977→    color: index % 2 === 0
   978→      ? [255, 255, 255, Math.round(opacity * 255)]
   979→      : [248, 250, 252, Math.round(opacity * 255)]
   980→  }));
   981→
   982→  layers.push(
   983→    new SolidPolygonLayer<RowBackground>({
   984→      id: 'micro-row-backgrounds',
   985→      data: rowBackgrounds,
   986→      getPolygon: d => d.polygon,
   987→      getFillColor: d => d.color,
   988→      extruded: false,
   989→      pickable: false
   990→    })
   991→  );
   992→
   993→  // 2. Grid lines (weekly)
   994→  const gridLines: GridLine[] = [];
   995→  for (let day = DAYS_PER_WEEK; day < totalDays; day += DAYS_PER_WEEK) {
   996→    if (day * pxPerDay < viewportBounds.minX - 100 || day * pxPerDay > viewportBounds.maxX + 100) continue;
   997→    gridLines.push({
   998→      path: [[day * pxPerDay, 0], [day * pxPerDay, -trains.length * pxPerTrain]],
   999→      color: [226, 232, 240, Math.round(opacity * 255)] // slate-200
  1000→    });
  1001→  }
  1002→
  1003→  layers.push(
  1004→    new PathLayer<GridLine>({
  1005→      id: 'micro-grid-lines',
  1006→      data: gridLines,
  1007→      getPath: d => d.path,
  1008→      getColor: d => d.color,
  1009→      getWidth: 1,
  1010→      widthUnits: 'pixels'
  1011→    })
  1012→  );
  1013→
