  1030→          ),
  1031→          color: [CONFLICT_COLOR[0], CONFLICT_COLOR[1], CONFLICT_COLOR[2], Math.round(CONFLICT_COLOR[3] * opacity)]
  1032→        })),
  1033→        getPolygon: d => d.polygon,
  1034→        getFillColor: d => d.color,
  1035→        extruded: false,
  1036→        pickable: false
  1037→      })
  1038→    );
  1039→  }
  1040→
  1041→  // 4. Focus ring
  1042→  if (focusedTaskId) {
  1043→    const focusedTask = taskMap.get(focusedTaskId);
  1044→    if (focusedTask) {
  1045→      layers.push(
  1046→        new SolidPolygonLayer({
  1047→          id: 'micro-focus-ring',
  1048→          data: [{
