  1052→              focusedTask.duration * pxPerDay + 8,
  1053→              TASK_HEIGHT + 8
  1054→            ),
  1055→            color: [FOCUS_COLOR[0], FOCUS_COLOR[1], FOCUS_COLOR[2], Math.round(FOCUS_COLOR[3] * opacity)]
  1056→          }],
  1057→          getPolygon: d => d.polygon,
  1058→          getFillColor: d => d.color,
  1059→          extruded: false,
  1060→          pickable: false
  1061→        })
  1062→      );
  1063→    }
  1064→  }
  1065→
  1066→  // 5. Task cards
  1067→  const taskCards: TaskCard[] = visibleTasks.map(task => ({
  1068→    id: task.id,
  1069→    polygon: createRectPolygon(
  1070→      task.startDay * pxPerDay,
  1071→      -task.trainIndex * pxPerTrain - TASK_PADDING,
  1072→      task.duration * pxPerDay,
  1073→      TASK_HEIGHT
  1074→    ),
  1075→    color: getTaskColor(task, task.id === hoveredTaskId, task.id === selectedTaskId),
  1076→    task
  1077→  }));
  1078→
  1079→  layers.push(
  1080→    new SolidPolygonLayer<TaskCard>({
