  1089→      }
  1090→    })
  1091→  );
  1092→
  1093→  // 6. Text labels (prioritized by width, max 50)
  1094→  const labelableTasks = visibleTasks
  1095→    .map(task => ({ task, width: task.duration * pxPerDay }))
