  1128→  }
  1129→
  1130→  // 7. Dependency arrows
  1131→  const dependencyPaths: DependencyPath[] = [];
  1132→  for (const task of visibleTasks) {
  1133→    if (task.predecessorId) {
  1134→      const predecessor = taskMap.get(task.predecessorId);
  1135→      if (predecessor) {
  1136→        dependencyPaths.push({
  1137→          path: createDependencyPath(predecessor, task, taskMap),
  1138→          color: [DEPENDENCY_COLOR[0], DEPENDENCY_COLOR[1], DEPENDENCY_COLOR[2], Math.round(DEPENDENCY_COLOR[3] * opacity)]
  1139→        });
  1140→      }
  1141→    }
  1142→  }
  1143→
  1144→  if (dependencyPaths.length > 0) {
  1145→    layers.push(
  1146→      new PathLayer<DependencyPath>({
  1147→        id: 'micro-dependency-arrows',
  1148→        data: dependencyPaths,
  1149→        getPath: d => d.path,
  1150→        getColor: d => d.color,
  1151→        getWidth: 2,
  1152→        widthUnits: 'pixels',
  1153→        capRounded: true,
  1154→        jointRounded: true
  1155→      })
  1156→    );
  1157→  }
  1158→
  1159→  return layers;
  1160→}
