  1199→  firstVisibleTrain: number;
  1200→  lastVisibleTrain: number;
  1201→  visibleTrains: number;
  1202→}
  1203→
  1204→export interface NavigationTarget {
  1205→  type: 'task' | 'train' | 'date';
  1206→  id?: string;
  1207→  trainIndex?: number;
  1208→  day?: number;
  1209→}
  1210→
  1211→export interface DeckCanvasProps {
  1212→  zoom: number;
  1213→  lod: LODLevel;
  1214→  onZoomChange: (zoom: number) => void;
  1215→  onViewportChange?: (viewport: ViewportInfo) => void;
  1216→  onMinZoomChange?: (minZoom: number) => void;
  1217→  animatedZoomTarget?: number | null;
  1218→  onAnimatedZoomComplete?: () => void;
  1219→  navigationTarget?: NavigationTarget | null;
  1220→  onNavigationComplete?: () => void;
  1221→  perfVisible?: boolean;
  1222→  perfEvent?: string;
  1223→}
  1224→
  1225→const { pxPerDay, pxPerTrain, lodThresholds } = DEFAULT_VIEW_CONFIG;
  1226→
  1227→// Zoom conversion functions (deck.gl uses log2 scale)
  1228→function linearToDeckZoom(linearZoom: number): number {
  1229→  return Math.log2(linearZoom);
  1230→}
  1231→
  1232→function deckToLinearZoom(deckZoom: number): number {
  1233→  return Math.pow(2, deckZoom);
  1234→}
  1235→
  1236→// LOD opacity calculation with hysteresis
  1237→function calculateLODOpacities(zoom: number): { macro: number; meso: number; micro: number } {
  1238→  const HYSTERESIS = 0.15; // 15% overlap zone
  1239→
  1240→  const macroThreshold = lodThresholds.macro;
  1241→  const microThreshold = lodThresholds.micro;
  1242→
  1243→  let macro = 0, meso = 0, micro = 0;
  1244→
  1245→  if (zoom < macroThreshold * (1 - HYSTERESIS)) {
  1246→    macro = 1;
  1247→  } else if (zoom < macroThreshold * (1 + HYSTERESIS)) {
  1248→    const t = (zoom - macroThreshold * (1 - HYSTERESIS)) / (macroThreshold * 2 * HYSTERESIS);
  1249→    macro = 1 - smoothstep(t);
  1250→    meso = smoothstep(t);
  1251→  } else if (zoom < microThreshold * (1 - HYSTERESIS)) {
  1252→    meso = 1;
  1253→  } else if (zoom < microThreshold * (1 + HYSTERESIS)) {
  1254→    const t = (zoom - microThreshold * (1 - HYSTERESIS)) / (microThreshold * 2 * HYSTERESIS);
  1255→    meso = 1 - smoothstep(t);
  1256→    micro = smoothstep(t);
  1257→  } else {
  1258→    micro = 1;
  1259→  }
  1260→
  1261→  return { macro, meso, micro };
  1262→}
  1263→
  1264→function smoothstep(t: number): number {
  1265→  t = Math.max(0, Math.min(1, t));
  1266→  return t * t * (3 - 2 * t);
  1267→}
  1268→
  1269→// Spatial index for viewport culling
  1270→interface TaskBBox {
  1271→  minX: number;
  1272→  minY: number;
  1273→  maxX: number;
  1274→  maxY: number;
  1275→  task: TaskRender;
  1276→}
  1277→
  1278→function createSpatialIndex(tasks: TaskRender[]): RBush<TaskBBox> {
  1279→  const tree = new RBush<TaskBBox>();
  1280→  const items = tasks.map(task => ({
  1281→    minX: task.startDay * pxPerDay,
  1282→    minY: -task.trainIndex * pxPerTrain - pxPerTrain,
  1283→    maxX: (task.startDay + task.duration) * pxPerDay,
  1284→    maxY: -task.trainIndex * pxPerTrain,
  1285→    task
  1286→  }));
  1287→  tree.load(items);
  1288→  return tree;
  1289→}
  1290→
  1291→export function DeckCanvas({
  1292→  zoom,
  1293→  lod: _lod,
  1294→  onZoomChange,
  1295→  onViewportChange,
  1296→  onMinZoomChange,
  1297→  animatedZoomTarget,
  1298→  onAnimatedZoomComplete,
  1299→  navigationTarget,
  1300→  onNavigationComplete,
  1301→  perfVisible: _perfVisible,
  1302→  perfEvent: _perfEvent,
  1303→}: DeckCanvasProps) {
  1304→  const containerRef = useRef<HTMLDivElement>(null);
  1305→  const [containerSize, setContainerSize] = useState({ width: 800, height: 600 });
  1306→
  1307→  // Get data from state
  1308→  const { tasks, meta } = canvasStore.getState().data ?? { tasks: [], trains: [], meta: { totalDays: 3650, startDate: '2024-01-01' } };
  1309→  const trains = useMemo(() =>
  1310→    Array.from({ length: 50 }, (_, i) => ({ id: `TRAIN-${String(i + 1).padStart(3, '0')}`, name: `Train ${i + 1}` })),
  1311→    []
  1312→  );
  1313→
  1314→  // Interaction state
  1315→  const hoveredTaskId = useCanvasSelector(s => s.interaction.hoveredTaskId);
  1316→  const selectedTaskId = useCanvasSelector(s => s.interaction.selectedTaskId);
  1317→  const focusedTaskId = useCanvasSelector(s => s.interaction.focusedTaskId);
  1318→
  1319→  // Create spatial index
  1320→  const spatialIndex = useMemo(() => createSpatialIndex(tasks), [tasks]);
  1321→
  1322→  // View state
  1323→  const [viewState, setViewState] = useState<DeckViewState>(() => ({
  1324→    target: [meta.totalDays * pxPerDay / 2, -trains.length * pxPerTrain / 2],
  1325→    zoom: linearToDeckZoom(zoom),
  1326→    minZoom: linearToDeckZoom(0.1),
  1327→    maxZoom: linearToDeckZoom(5)
  1328→  }));
  1329→
  1330→  // Handle container resize
  1331→  useEffect(() => {
  1332→    if (!containerRef.current) return;
  1333→
  1334→    const observer = new ResizeObserver(entries => {
  1335→      const entry = entries[0];
  1336→      if (entry) {
  1337→        setContainerSize({
  1338→          width: entry.contentRect.width,
  1339→          height: entry.contentRect.height
  1340→        });
  1341→      }
  1342→    });
  1343→
  1344→    observer.observe(containerRef.current);
  1345→    return () => observer.disconnect();
  1346→  }, []);
  1347→
  1348→  // Calculate viewport bounds
  1349→  const viewportBounds = useMemo(() => {
  1350→    const linearZ = deckToLinearZoom(viewState.zoom);
  1351→    const halfW = containerSize.width / 2 / linearZ;
  1352→    const halfH = containerSize.height / 2 / linearZ;
  1353→    return {
  1354→      minX: viewState.target[0] - halfW,
  1355→      maxX: viewState.target[0] + halfW,
  1356→      minY: viewState.target[1] - halfH,
  1357→      maxY: viewState.target[1] + halfH
  1358→    };
  1359→  }, [viewState, containerSize]);
  1360→
  1361→  // Calculate LOD opacities
  1362→  const lodOpacities = useMemo(
  1363→    () => calculateLODOpacities(deckToLinearZoom(viewState.zoom)),
  1364→    [viewState.zoom]
  1365→  );
  1366→
  1367→  // Create layers based on LOD
  1368→  const layers = useMemo(() => {
  1369→    const totalDays = meta.totalDays;
  1370→    const allLayers: any[] = [];
  1371→
  1372→    if (lodOpacities.macro > 0) {
  1373→      allLayers.push(...createMacroLayers({
  1374→        tasks,
  1375→        trains,
  1376→        opacity: lodOpacities.macro,
  1377→        totalDays
  1378→      }));
  1379→    }
  1380→
  1381→    if (lodOpacities.meso > 0) {
  1382→      allLayers.push(...createMesoLayers({
  1383→        tasks,
  1384→        trains,
  1385→        opacity: lodOpacities.meso,
  1386→        totalDays,
  1387→        hoveredTaskId,
  1388→        selectedTaskId,
  1389→        focusedTaskId,
  1390→        viewportBounds
  1391→      }));
  1392→    }
  1393→
  1394→    if (lodOpacities.micro > 0) {
  1395→      allLayers.push(...createMicroLayers({
  1396→        tasks,
  1397→        trains,
  1398→        opacity: lodOpacities.micro,
  1399→        totalDays,
  1400→        hoveredTaskId,
  1401→        selectedTaskId,
  1402→        focusedTaskId,
  1403→        viewportBounds
  1404→      }));
  1405→    }
  1406→
  1407→    return allLayers;
  1408→  }, [tasks, trains, lodOpacities, hoveredTaskId, selectedTaskId, focusedTaskId, viewportBounds]);
  1409→
  1410→  // Handle view state change
  1411→  const handleViewStateChange = useCallback(({ viewState: newViewState }: { viewState: DeckViewState }) => {
  1412→    setViewState(newViewState);
  1413→    const linearZoom = deckToLinearZoom(newViewState.zoom);
  1414→    onZoomChange(linearZoom);
  1415→
  1416→    // Update viewport info
  1417→    if (onViewportChange) {
  1418→      const z = linearZoom;
  1419→      const halfW = containerSize.width / 2 / z;
  1420→      const startDay = Math.max(0, (newViewState.target[0] - halfW) / pxPerDay);
  1421→      const endDay = Math.min(meta.totalDays, (newViewState.target[0] + halfW) / pxPerDay);
  1422→
  1423→      onViewportChange({
  1424→        startDay,
  1425→        endDay,
  1426→        centerDay: (startDay + endDay) / 2,
  1427→        visibleDays: endDay - startDay,
  1428→        firstVisibleTrain: 0,
  1429→        lastVisibleTrain: trains.length - 1,
  1430→        visibleTrains: trains.length
  1431→      });
  1432→    }
  1433→  }, [onZoomChange, onViewportChange, containerSize, meta.totalDays, trains.length]);
  1434→
  1435→  // Handle hover
  1436→  const handleHover = useCallback((info: any) => {
  1437→    if (info.object?.task) {
  1438→      canvasStore.dispatch(canvasActions.interaction.setHoveredTask(info.object.task.id));
  1439→    } else {
  1440→      canvasStore.dispatch(canvasActions.interaction.clearHover(null));
  1441→    }
  1442→  }, []);
  1443→
  1444→  // Handle click
  1445→  const handleClick = useCallback((info: any) => {
  1446→    if (info.object?.task) {
  1447→      canvasStore.dispatch(canvasActions.interaction.setSelectedTask(info.object.task.id));
  1448→    } else {
  1449→      canvasStore.dispatch(canvasActions.interaction.clearSelection(null));
  1450→    }
  1451→  }, []);
  1452→
  1453→  // OrthographicView for timeline
  1454→  const views = new OrthographicView({
  1455→    id: 'timeline',
  1456→    flipY: false,
  1457→    controller: {
  1458→      scrollZoom: true,
  1459→      dragPan: true,
  1460→      doubleClickZoom: true,
  1461→      touchRotate: false,
  1462→      keyboard: true
  1463→    }
  1464→  });
  1465→
  1466→  return (
  1467→    <div
  1468→      ref={containerRef}
  1469→      style={{ width: '100%', height: '100%', position: 'relative', background: '#f4f4f5' }}
  1470→    >
  1471→      <DeckGL
  1472→        views={views}
  1473→        viewState={viewState}
  1474→        onViewStateChange={handleViewStateChange as any}
  1475→        controller={true}
  1476→        layers={layers}
  1477→        onHover={handleHover}
  1478→        onClick={handleClick}
  1479→        width="100%"
  1480→        height="100%"
  1481→      />
  1482→
  1483→      {/* LOD indicator */}
  1484→      <div
  1485→        style={{
  1486→          position: 'absolute',
  1487→          top: '8px',
  1488→          right: '8px',
  1489→          padding: '4px 8px',
  1490→          background: 'rgba(0,0,0,0.7)',
  1491→          color: 'white',
  1492→          fontSize: '12px',
  1493→          borderRadius: '4px'
  1494→        }}
  1495→      >
  1496→        {lodOpacities.macro > 0.5 ? 'MACRO' : lodOpacities.micro > 0.5 ? 'MICRO' : 'MESO'}
  1497→        {' | '}
  1498→        {deckToLinearZoom(viewState.zoom).toFixed(2)}x
  1499→      </div>
  1500→    </div>
  1501→  );
  1502→}
  1503→```
