  1597→```typescript
  1598→/**
  1599→ * Canvas State Machine - @mms/toolkit integration
  1600→ * Uses typed selectors to avoid 'unknown' type issues
  1601→ */
  1602→import { createMachine, createSyncSlice } from '@mms/toolkit';
  1603→import { viewportSlice, ViewportSliceState } from './viewport';
