  1748→### 10. Mock Data Generator
  1749→
  1750→**File:** `apps/canvas/src/data/generator.ts`
  1751→
  1752→Seeded random for deterministic 50 trains x 10 years test data.
  1753→
  1754→```typescript
  1755→/**
  1756→ * Mock Data Generator
  1757→ * Pre-generates deterministic data: 50 trains x 10 years
  1758→ * Uses seeded random for reproducible results
  1759→ */
  1760→import type { TaskRender, Train, RenderData, DataMeta, TaskType, TaskColor } from './types';
  1761→
  1762→// Seeded random number generator
  1763→function createSeededRandom(seed: number) {
  1764→  let s = seed;
  1765→  return () => {
  1766→    s = (s * 1103515245 + 12345) & 0x7fffffff;
  1767→    return s / 0x7fffffff;
  1768→  };
  1769→}
  1770→
  1771→const TASK_TYPES: TaskType[] = ['maintenance', 'overhaul', 'inspection'];
  1772→const TYPE_WEIGHTS = [0.6, 0.25, 0.15]; // 60% maintenance, 25% overhaul, 15% inspection
  1773→const TYPE_COLORS: Record<TaskType, TaskColor> = {
  1774→  maintenance: 'blue',
  1775→  overhaul: 'orange',
  1776→  inspection: 'gray'
  1777→};
  1778→
  1779→function selectType(rand: () => number): TaskType {
  1780→  const r = rand();
  1781→  let cumulative = 0;
  1782→  for (let i = 0; i < TASK_TYPES.length; i++) {
  1783→    cumulative += TYPE_WEIGHTS[i];
  1784→    if (r < cumulative) return TASK_TYPES[i];
  1785→  }
  1786→  return TASK_TYPES[0];
  1787→}
  1788→
  1789→export function generateRenderData(seed = 42): RenderData {
  1790→  const rand = createSeededRandom(seed);
  1791→
  1792→  const NUM_TRAINS = 50;
  1793→  const TOTAL_DAYS = 3650; // 10 years
  1794→  const TASKS_PER_TRAIN_PER_YEAR = 4; // ~4 tasks per train per year
  1795→
  1796→  const trains: Train[] = Array.from({ length: NUM_TRAINS }, (_, i) => ({
  1797→    id: `TRAIN-${String(i + 1).padStart(3, '0')}`,
  1798→    name: `Train ${i + 1}`
  1799→  }));
  1800→
  1801→  const tasks: TaskRender[] = [];
  1802→  let taskId = 1;
  1803→
  1804→  for (let trainIndex = 0; trainIndex < NUM_TRAINS; trainIndex++) {
  1805→    const numTasks = Math.round(TASKS_PER_TRAIN_PER_YEAR * 10 * (0.8 + rand() * 0.4));
  1806→
  1807→    for (let t = 0; t < numTasks; t++) {
  1808→      const type = selectType(rand);
  1809→      const startDay = Math.floor(rand() * (TOTAL_DAYS - 30));
  1810→      const duration = Math.floor(5 + rand() * 25); // 5-30 days
  1811→      const hasConflict = rand() < 0.15; // 15% chance
  1812→      const hasPredecessor = rand() < 0.3; // 30% chance
  1813→
  1814→      tasks.push({
  1815→        id: `TASK-${String(taskId++).padStart(5, '0')}`,
  1816→        trainIndex,
  1817→        startDay,
  1818→        duration,
  1819→        type,
  1820→        color: TYPE_COLORS[type],
  1821→        hasConflict,
  1822→        predecessorId: hasPredecessor && taskId > 2
  1823→          ? `TASK-${String(Math.floor(rand() * (taskId - 1)) + 1).padStart(5, '0')}`
  1824→          : undefined
  1825→      });
  1826→    }
  1827→  }
  1828→
  1829→  const meta: DataMeta = {
  1830→    startDate: '2024-01-01',
  1831→    totalDays: TOTAL_DAYS
  1832→  };
  1833→
  1834→  return { tasks, trains, meta };
  1835→}
  1836→
  1837→// Cached render data
  1838→let cachedData: RenderData | null = null;
  1839→
  1840→export function getRenderData(): RenderData {
  1841→  if (!cachedData) {
  1842→    cachedData = generateRenderData();
  1843→  }
  1844→  return cachedData;
  1845→}
  1846→```
  1847→
  1848→---
  1849→
  1850→### 11. Performance Monitor (Pure React)
  1851→
  1852→**File:** `apps/canvas/src/components/PerfMonitor.tsx`
  1853→
  1854→FPS tracking without r3f-perf dependency.
  1855→
  1856→```typescript
  1857→/**
  1858→ * Performance Monitor - Pure React implementation (no r3f-perf dependency)
  1859→ * Provides FPS display and performance event tracking
  1860→ */
  1861→import { useEffect, useCallback, useState, useRef } from 'react';
  1862→
  1863→export type PerfEvent = 'idle' | 'panning' | 'zooming' | 'animating' | 'lod_transition' | 'unknown';
  1864→
  1865→export function usePerfMonitorToggle(initialVisible = false) {
  1866→  const [visible, setVisible] = useState(initialVisible);
  1867→
  1868→  useEffect(() => {
  1869→    const handleKeyDown = (e: KeyboardEvent) => {
  1870→      if (e.key === 'p' && !e.ctrlKey && !e.metaKey && !e.altKey &&
  1871→          !(e.target instanceof HTMLInputElement) &&
  1872→          !(e.target instanceof HTMLTextAreaElement)) {
  1873→        setVisible((v) => !v);
  1874→      }
  1875→    };
  1876→    window.addEventListener('keydown', handleKeyDown);
  1877→    return () => window.removeEventListener('keydown', handleKeyDown);
  1878→  }, []);
  1879→
  1880→  const toggle = useCallback(() => setVisible((v) => !v), []);
  1881→  return { visible, toggle, setVisible };
  1882→}
  1883→
  1884→interface FPSStats {
  1885→  fps: number;
  1886→  avg: number;
  1887→  min: number;
  1888→  frameTime: number;
  1889→}
  1890→
  1891→export function useFPSMonitor(): FPSStats {
  1892→  const [stats, setStats] = useState<FPSStats>({ fps: 60, avg: 60, min: 60, frameTime: 16.67 });
  1893→  const frameTimesRef = useRef<number[]>([]);
  1894→  const lastTimeRef = useRef(performance.now());
  1895→
  1896→  useEffect(() => {
  1897→    let animationId: number;
  1898→
  1899→    const measure = () => {
  1900→      const now = performance.now();
  1901→      const delta = now - lastTimeRef.current;
  1902→      lastTimeRef.current = now;
  1903→
  1904→      frameTimesRef.current.push(delta);
  1905→      if (frameTimesRef.current.length > 60) {
  1906→        frameTimesRef.current.shift();
  1907→      }
  1908→
  1909→      const times = frameTimesRef.current;
  1910→      const avgTime = times.reduce((a, b) => a + b, 0) / times.length;
  1911→      const maxTime = Math.max(...times);
  1912→
  1913→      setStats({
  1914→        fps: Math.round(1000 / delta),
  1915→        avg: Math.round(1000 / avgTime),
  1916→        min: Math.round(1000 / maxTime),
  1917→        frameTime: Math.round(avgTime * 100) / 100
  1918→      });
  1919→
  1920→      animationId = requestAnimationFrame(measure);
  1921→    };
  1922→
  1923→    animationId = requestAnimationFrame(measure);
  1924→    return () => cancelAnimationFrame(animationId);
  1925→  }, []);
  1926→
  1927→  return stats;
  1928→}
  1929→
  1930→interface PerfMonitorProps {
  1931→  visible?: boolean;
  1932→  event?: PerfEvent;
  1933→}
  1934→
  1935→export function PerfMonitor({ visible = true, event = 'idle' }: PerfMonitorProps) {
  1936→  const stats = useFPSMonitor();
  1937→
  1938→  if (!visible) return null;
  1939→
  1940→  const fpsColor = stats.fps >= 55 ? '#22c55e' : stats.fps >= 30 ? '#eab308' : '#ef4444';
  1941→
  1942→  return (
  1943→    <div
  1944→      style={{
  1945→        position: 'absolute',
  1946→        top: 8,
  1947→        left: 8,
  1948→        padding: '8px 12px',
  1949→        background: 'rgba(0, 0, 0, 0.75)',
  1950→        color: 'white',
  1951→        fontFamily: 'monospace',
  1952→        fontSize: '12px',
  1953→        borderRadius: '4px',
  1954→        lineHeight: 1.4,
  1955→        minWidth: '120px'
  1956→      }}
  1957→    >
  1958→      <div style={{ color: fpsColor, fontWeight: 'bold' }}>
  1959→        FPS: {stats.fps}
  1960→      </div>
  1961→      <div>Avg: {stats.avg}</div>
  1962→      <div>Min: {stats.min}</div>
  1963→      <div>Frame: {stats.frameTime}ms</div>
  1964→      <div style={{ marginTop: 4, color: '#94a3b8', textTransform: 'uppercase', fontSize: '10px' }}>
  1965→        {event}
  1966→      </div>
  1967→    </div>
  1968→  );
  1969→}
  1970→```
  1971→
  1972→---
  1973→
  1974→## Anti-Patterns (What Failed)
  1975→
  1976→### 1. PixiJS v8 API Changes
  1977→
  1978→**Error:** `Cannot read properties of null (reading 'updateLocalTransform')`
  1979→
  1980→**Why Failed:** PixiJS v8 changed API - components accessed before initialization or after destruction
  1981→
  1982→**Lesson:** ALWAYS check PixiJS v8 API changes - v8 has breaking changes from v7. Never access PixiJS internals without null guards.
  1983→
  1984→---
  1985→
  1986→### 2. React StrictMode Canvas Cleanup
  1987→
  1988→**Error:** Multiple canvas elements created - StrictMode runs effects twice
  1989→
  1990→**Why Failed:** React 18 StrictMode double-invokes effects for development. PixiJS Application created twice but cleanup only removed one.
  1991→
  1992→**Lesson:** React StrictMode in development mode runs useEffect TWICE. Canvas cleanup MUST handle multiple instances. Track canvas refs explicitly.
  1993→
  1994→---
  1995→
  1996→### 3. Blank Screen in Storybook
  1997→
  1998→**Error:** Tela branca no Storybook - no visual output
  1999→
  2000→**Why Failed:** JavaScript error in PixiJS initialization prevented rendering, but no console error visible in Storybook wrapper.
  2001→
  2002→**Lesson:** ALWAYS test in Storybook IFRAME view directly, not in Storybook wrapper. Wrapper hides JavaScript errors.
  2003→
  2004→---
  2005→
  2006→### 4. BlueprintJS CSS Customization
  2007→
  2008→**Error:** Dark mode only changes background and some text colors
  2009→
  2010→**Why Failed:** User explicitly rejected custom CSS approach. AI kept adding custom overrides instead of using native Blueprint styling.
  2011→
  2012→**Lesson:** Do NOT customize component library CSS. Use ONLY native props/classes. Blueprint Intent system, Classes object, Elevation enum - never `var(--custom)` or inline styles for theming.
  2013→
  2014→---
  2015→
  2016→### 5. Hallucinated Blueprint Classes
  2017→
  2018→**Error:** `Classes.FLEX_CONTAINER does not exist in Blueprint.js`
  2019→
  2020→**Why Failed:** AI hallucinated a Blueprint class that doesn't exist. Used training data instead of checking actual API.
  2021→
  2022→**Lesson:** NEVER assume CSS classes exist. Always VERIFY against current docs.
  2023→
  2024→---
  2025→
  2026→### 6. Blueprint Dark Mode Background
  2027→
  2028→**Error:** Dark mode not visually applying - background stayed white/transparent
  2029→
  2030→**Why Failed:** Blueprint.js only styles components, not page body. Used wrong dark color.
  2031→
  2032→**Lesson:** Blueprint ONLY styles its components, NOT body/page. Must add body background manually. Use OFFICIAL colors: light=#f6f7f9, dark=#1c2127.
  2033→
  2034→---
  2035→
  2036→### 7. XState Assumption
  2037→
  2038→**Error:** "@mms/toolkit nao usa xstate"
  2039→
  2040→**Why Failed:** AI assumed XState was used based on training patterns. Actual toolkit uses custom store with immer + useSyncExternalStore.
  2041→
  2042→**Lesson:** NEVER assume state management library. Check package.json dependencies.
  2043→
  2044→---
  2045→
  2046→### 8. Zustand TypedArray Reactivity
  2047→
  2048→**Error:** State mutations not triggering re-renders
  2049→
  2050→**Why Failed:** Zustand with TypedArrays - direct mutation doesn't trigger subscription notifications.
  2051→
  2052→**Lesson:** TypedArrays with Zustand: direct mutation BYPASSES reactivity. Must explicitly call `set()` or trigger version bump after mutations.
  2053→
  2054→---
  2055→
  2056→### 9. AI Duplicate Interface Injection (Gemini)
  2057→
  2058→**Error:** Duplicate interface definition completely breaking the file
  2059→
  2060→**Why Failed:** AI (Gemini) inserted code at wrong location, breaking TypeScript syntax.
  2061→
  2062→**Lesson:** AI can insert code at WRONG LOCATIONS. Always run typecheck immediately after AI edits.
  2063→
  2064→---
  2065→
  2066→### 10. use-gesture Hook Usage
  2067→
  2068→**Error:** `TypeError: gestureBind is not a function`
  2069→
  2070→**Why Failed:** @use-gesture/react hook returns bind function, but implementation used it incorrectly.
  2071→
  2072→**Lesson:** use-gesture returns a BIND FUNCTION, not an object. Spread bind() result on target element.
  2073→
  2074→---
  2075→
  2076→### 11. Tests Passing But App Broken
  2077→
  2078→**Error:** "O site continua quebrando e nenhum teste conectou - tela branca"
  2079→
  2080→**Why Failed:** Unit tests passed but didn't test actual rendering. E2E tests didn't capture console errors.
  2081→
  2082→**Lesson:** Tests passing !== App working. MUST visual verify with Playwright. Check console.error.
  2083→
  2084→---
  2085→
  2086→### 12. RBush in Wrong Phase
  2087→
  2088→**Error:** "RBush e Estrutural, nao Polimento"
  2089→
  2090→**Why Failed:** AI treated performance optimization as polish. RBush is STRUCTURAL requirement for 60k items.
  2091→
  2092→**Lesson:** Spatial indexing (RBush/Flatbush) is STRUCTURAL, not polish. Required for any interaction with large datasets.
  2093→
  2094→---
  2095→
  2096→### 13. Incomplete Architecture Pivot
  2097→
  2098→**Error:** Arquivos Astro ainda existem apos pivot para PixiJS/Vite
  2099→
  2100→**Why Failed:** Architecture pivot was incomplete. Old files not removed, new files not created.
  2101→
  2102→**Lesson:** Architecture pivots must be COMPLETE. Remove ALL old framework files.
  2103→
  2104→---
  2105→
  2106→### 14. Documentation Drift
  2107→
  2108→**Error:** Divergencias entre documentacao e codigo atual
  2109→
  2110→**Why Failed:** Documentation was updated optimistically before code was written.
  2111→
  2112→**Lesson:** Treat documentation as CODE. Verify against reality.
  2113→
  2114→---
  2115→
  2116→## Key Takeaways
  2117→
  2118→### Architecture
  2119→1. **SoA over AoS** - Structure of Arrays with TypedArrays for cache performance
  2120→2. **Two-layer data** - Persistent (JSON) vs Rendering (computed) types
  2121→3. **RBush is STRUCTURAL** - Spatial indexing required for 60k+ items, not polish
  2122→4. **deck.gl OrthographicView** - Use log2 zoom scale, handle view state changes
  2123→
  2124→### State Management
  2125→1. **@mms/toolkit NOT XState** - Custom store with immer + useSyncExternalStore
  2126→2. **TypedArray reactivity** - Must explicitly call set() after mutations
  2127→3. **Hysteresis in LOD** - 15% overlap zones prevent flickering
  2128→
  2129→### Common Failures
  2130→1. **Blank screen** - Always check Storybook iframe directly
  2131→2. **Tests passing** - Visual verification with Playwright required
  2132→3. **CSS customization** - Use only native Blueprint classes, never custom vars
  2133→4. **Hallucinated APIs** - Always verify against current docs
  2134→5. **Documentation drift** - Treat docs as code, verify against reality
  2135→

