# Code Patterns - MMS

> Consolidated from EXTRACT-CODE-001.jsonl (working patterns) and EXTRACT-CODE-002.jsonl (anti-patterns)

---

## Working Code Patterns

### 1. SimulationStore - Structure of Arrays (SoA) with TypedArrays

**File:** `src/engine/stores/SimulationStore.ts`

Complete SoA store using TypedArrays for high-performance scheduling data with Zustand.

```typescript
/**
 * SimulationStore - Structure of Arrays (SoA) Implementation
 *
 * This store manages schedule block data using TypedArrays for optimal
 * cache performance and minimal GC pressure. All bulk operations work
 * directly on contiguous memory.
 *
 * Architecture Decision: We use SoA instead of AoS (Array of Structures)
 * because timeline operations typically iterate over single properties
 * (e.g., all start times for collision detection) rather than all
 * properties of single blocks.
 */

import { create } from 'zustand';
import { subscribeWithSelector } from 'zustand/middleware';
import { IntervalTree } from '../core/IntervalTree';
import type { BlockType, BlockStatus, ScheduleBlockInput } from '../types';

/** Initial capacity - will grow dynamically */
const INITIAL_CAPACITY = 1024;

/** Growth factor when resizing arrays */
const GROWTH_FACTOR = 2;

/** Block type to numeric index mapping for TypedArray storage */
const BLOCK_TYPE_INDEX: Record<BlockType, number> = {
  A_CHECK: 0,
  B_CHECK: 1,
  C_CHECK: 2,
  D_CHECK: 3,
  ENGINE_OVERHAUL: 4,
  LANDING_GEAR: 5,
  APU_SERVICE: 6,
  INTERIOR_REFURB: 7,
  PAINT: 8,
  MOD_UPGRADE: 9,
  AOG_REPAIR: 10,
  LEASE_RETURN: 11,
  CUSTOM: 12,
};

/** Reverse mapping for retrieving block type from index */
const INDEX_TO_BLOCK_TYPE: BlockType[] = [
  'A_CHECK',
  'B_CHECK',
  'C_CHECK',
  'D_CHECK',
  'ENGINE_OVERHAUL',
  'LANDING_GEAR',
  'APU_SERVICE',
  'INTERIOR_REFURB',
  'PAINT',
  'MOD_UPGRADE',
  'AOG_REPAIR',
  'LEASE_RETURN',
  'CUSTOM',
];

/**
 * Structure of Arrays data container
 * Each array index corresponds to the same block entity
 */
interface SoAData {
  /** Block start timestamps in milliseconds */
  startMs: Float64Array;
  /** Block durations in milliseconds */
  durationMs: Float64Array;
  /** Aircraft row indices */
  aircraftIndex: Uint16Array;
  /** Block type indices (see BLOCK_TYPE_INDEX) */
  typeIndex: Uint8Array;
  /** Block status (0=scheduled, 1=in-progress, 2=completed, 3=cancelled) */
  status: Uint8Array;
  /** Unique block IDs for external reference */
  ids: Uint32Array;
}

interface SimulationState {
  /** SoA data arrays */
  data: SoAData;
  /** Current number of blocks */
  count: number;
  /** Current array capacity */
  capacity: number;
  /** Next available block ID */
  nextId: number;
  /** Interval tree for efficient range queries */
  intervalTree: IntervalTree;
  /** Currently selected block ID (null if none) */
  selectedBlockId: number | null;
  /** Viewport time range for visible blocks */
  viewportStart: number;
  viewportEnd: number;
}

interface SimulationActions {
  /** Add a new schedule block, returns the assigned ID */
  addBlock: (block: ScheduleBlockInput) => number;
  /** Update an existing block's properties */
  updateBlock: (id: number, updates: Partial<ScheduleBlockInput>) => void;
  /** Remove a block by ID */
  removeBlock: (id: number) => void;
  /** Query blocks within a time range */
  queryRange: (startMs: number, endMs: number) => number[];
  /** Set the currently selected block */
  selectBlock: (id: number | null) => void;
  /** Update viewport bounds for virtualization */
  setViewport: (startMs: number, endMs: number) => void;
  /** Get block data by ID */
  getBlock: (id: number) => {
    id: number;
    startMs: number;
    durationMs: number;
    aircraftIndex: number;
    type: BlockType;
    status: BlockStatus;
  } | null;
  /** Bulk load blocks (replaces existing data) */
  loadBlocks: (blocks: ScheduleBlockInput[]) => void;
  /** Clear all blocks */
  clear: () => void;
}

type SimulationStore = SimulationState & SimulationActions;

/**
 * Create initial SoA data structure with given capacity
 */
function createSoAData(capacity: number): SoAData {
  return {
    startMs: new Float64Array(capacity),
    durationMs: new Float64Array(capacity),
    aircraftIndex: new Uint16Array(capacity),
    typeIndex: new Uint8Array(capacity),
    status: new Uint8Array(capacity),
    ids: new Uint32Array(capacity),
  };
}

/**
 * Resize SoA arrays to new capacity, preserving existing data
 */
function resizeSoAData(data: SoAData, oldCount: number, newCapacity: number): SoAData {
  const newData = createSoAData(newCapacity);

  // Copy existing data
  newData.startMs.set(data.startMs.subarray(0, oldCount));
  newData.durationMs.set(data.durationMs.subarray(0, oldCount));
  newData.aircraftIndex.set(data.aircraftIndex.subarray(0, oldCount));
  newData.typeIndex.set(data.typeIndex.subarray(0, oldCount));
  newData.status.set(data.status.subarray(0, oldCount));
  newData.ids.set(data.ids.subarray(0, oldCount));

  return newData;
}

/**
 * Convert BlockStatus to numeric value
 */
function statusToNumber(status: BlockStatus): number {
  switch (status) {
    case 'scheduled':
      return 0;
    case 'in-progress':
      return 1;
    case 'completed':
      return 2;
    case 'cancelled':
      return 3;
    default:
      return 0;
  }
}

/**
 * Convert numeric value to BlockStatus
 */
function numberToStatus(num: number): BlockStatus {
  switch (num) {
    case 0:
      return 'scheduled';
    case 1:
      return 'in-progress';
    case 2:
      return 'completed';
    case 3:
      return 'cancelled';
    default:
      return 'scheduled';
  }
}

/**
 * Main simulation store using Zustand with SoA architecture
 */
export const useSimulationStore = create<SimulationStore>()(
  subscribeWithSelector((set, get) => ({
    // Initial state
    data: createSoAData(INITIAL_CAPACITY),
    count: 0,
    capacity: INITIAL_CAPACITY,
    nextId: 1,
    intervalTree: new IntervalTree(),
    selectedBlockId: null,
    viewportStart: 0,
    viewportEnd: Date.now() + 365 * 24 * 60 * 60 * 1000, // 1 year default

    addBlock: (block: ScheduleBlockInput): number => {
      const state = get();
      let { data, count, capacity, nextId, intervalTree } = state;

      // Grow arrays if needed
      if (count >= capacity) {
        const newCapacity = capacity * GROWTH_FACTOR;
        data = resizeSoAData(data, count, newCapacity);
        capacity = newCapacity;
      }

      // Assign ID and store block data
      const id = nextId;
      const index = count;

      data.ids[index] = id;
      data.startMs[index] = block.startMs;
      data.durationMs[index] = block.durationMs;
      data.aircraftIndex[index] = block.aircraftIndex;
      data.typeIndex[index] = BLOCK_TYPE_INDEX[block.type];
      data.status[index] = statusToNumber(block.status ?? 'scheduled');

      // Add to interval tree for range queries
      intervalTree.insert(block.startMs, block.startMs + block.durationMs, id);

      set({
        data,
        count: count + 1,
        capacity,
        nextId: nextId + 1,
        intervalTree,
      });

      return id;
    },

    updateBlock: (id: number, updates: Partial<ScheduleBlockInput>): void => {
      const state = get();
      const { data, count, intervalTree } = state;

      // Find block index by ID
      let index = -1;
      for (let i = 0; i < count; i++) {
        if (data.ids[i] === id) {
          index = i;
          break;
        }
      }

      if (index === -1) return;

      // Get old values for interval tree update
      const oldStart = data.startMs[index];
      const oldEnd = oldStart + data.durationMs[index];

      // Apply updates
      if (updates.startMs !== undefined) {
        data.startMs[index] = updates.startMs;
      }
      if (updates.durationMs !== undefined) {
        data.durationMs[index] = updates.durationMs;
      }
      if (updates.aircraftIndex !== undefined) {
        data.aircraftIndex[index] = updates.aircraftIndex;
      }
      if (updates.type !== undefined) {
        data.typeIndex[index] = BLOCK_TYPE_INDEX[updates.type];
      }
      if (updates.status !== undefined) {
        data.status[index] = statusToNumber(updates.status);
      }

      // Update interval tree if time changed
      if (updates.startMs !== undefined || updates.durationMs !== undefined) {
        intervalTree.remove(oldStart, oldEnd, id);
        const newStart = data.startMs[index];
        const newEnd = newStart + data.durationMs[index];
        intervalTree.insert(newStart, newEnd, id);
      }

      set({ data, intervalTree });
    },

    removeBlock: (id: number): void => {
      const state = get();
      const { data, intervalTree } = state;
      let { count } = state;

      // Find block index by ID
      let index = -1;
      for (let i = 0; i < count; i++) {
        if (data.ids[i] === id) {
          index = i;
          break;
        }
      }

      if (index === -1) return;

      // Remove from interval tree
      const start = data.startMs[index];
      const end = start + data.durationMs[index];
      intervalTree.remove(start, end, id);

      // Swap with last element and decrement count (avoids shifting)
      const lastIndex = count - 1;
      if (index !== lastIndex) {
        data.ids[index] = data.ids[lastIndex];
        data.startMs[index] = data.startMs[lastIndex];
        data.durationMs[index] = data.durationMs[lastIndex];
        data.aircraftIndex[index] = data.aircraftIndex[lastIndex];
        data.typeIndex[index] = data.typeIndex[lastIndex];
        data.status[index] = data.status[lastIndex];
      }

      set({ data, count: count - 1, intervalTree });
    },

    queryRange: (startMs: number, endMs: number): number[] => {
      const { intervalTree } = get();
      return intervalTree.query(startMs, endMs);
    },

    selectBlock: (id: number | null): void => {
      set({ selectedBlockId: id });
    },

    setViewport: (startMs: number, endMs: number): void => {
      set({ viewportStart: startMs, viewportEnd: endMs });
    },

    getBlock: (id: number) => {
      const { data, count } = get();

      // Find block index by ID
      for (let i = 0; i < count; i++) {
        if (data.ids[i] === id) {
          return {
            id,
            startMs: data.startMs[i],
            durationMs: data.durationMs[i],
            aircraftIndex: data.aircraftIndex[i],
            type: INDEX_TO_BLOCK_TYPE[data.typeIndex[i]],
            status: numberToStatus(data.status[i]),
          };
        }
      }

      return null;
    },

    loadBlocks: (blocks: ScheduleBlockInput[]): void => {
      const requiredCapacity = Math.max(INITIAL_CAPACITY, blocks.length);
      const data = createSoAData(requiredCapacity);
      const intervalTree = new IntervalTree();

      let nextId = 1;
      for (let i = 0; i < blocks.length; i++) {
        const block = blocks[i];
        data.ids[i] = nextId;
        data.startMs[i] = block.startMs;
        data.durationMs[i] = block.durationMs;
        data.aircraftIndex[i] = block.aircraftIndex;
        data.typeIndex[i] = BLOCK_TYPE_INDEX[block.type];
        data.status[i] = statusToNumber(block.status ?? 'scheduled');

        intervalTree.insert(block.startMs, block.startMs + block.durationMs, nextId);
        nextId++;
      }

      set({
        data,
        count: blocks.length,
        capacity: requiredCapacity,
        nextId,
        intervalTree,
        selectedBlockId: null,
      });
    },

    clear: (): void => {
      set({
        data: createSoAData(INITIAL_CAPACITY),
        count: 0,
        capacity: INITIAL_CAPACITY,
        nextId: 1,
        intervalTree: new IntervalTree(),
        selectedBlockId: null,
      });
    },
  }))
);

/**
 * Selector for getting visible blocks based on current viewport
 */
export const selectVisibleBlocks = (state: SimulationStore): number[] => {
  return state.queryRange(state.viewportStart, state.viewportEnd);
};

/**
 * Selector for getting blocks by aircraft index
 */
export const selectBlocksByAircraft = (
  state: SimulationStore,
  aircraftIndex: number
): number[] => {
  const { data, count } = state;
  const result: number[] = [];

  for (let i = 0; i < count; i++) {
    if (data.aircraftIndex[i] === aircraftIndex) {
      result.push(data.ids[i]);
    }
  }

  return result;
};
