### 2. MacroLayer - Heatmap View (Zoom < 0.5x)

**File:** `apps/canvas/src/deck/layers/MacroLayer.ts`

deck.gl SolidPolygonLayer for aggregated task density heatmap with d3-scale-chromatic color interpolation.

```typescript
/**
 * MacroLayer - Heatmap view for zoom < 0.5x
 * Uses SolidPolygonLayer to render aggregated task density cells
 */
import { SolidPolygonLayer } from '@deck.gl/layers';
import { interpolateYlOrRd } from 'd3-scale-chromatic';
import type { TaskRender, Train } from '../../data/types';
import { DEFAULT_VIEW_CONFIG } from '../../data/types';

const DAYS_PER_CELL = 30; // ~1 month per cell
const { pxPerDay, pxPerTrain } = DEFAULT_VIEW_CONFIG;
const CELL_WIDTH = DAYS_PER_CELL * pxPerDay; // 300px
const CELL_HEIGHT = pxPerTrain; // 24px

interface HeatmapCell {
  polygon: number[][];
  color: [number, number, number, number];
  taskCount: number;
}

interface YearMarker {
  polygon: number[][];
  color: [number, number, number, number];
}

function parseColorToRGBA(cssColor: string, alpha = 255): [number, number, number, number] {
  // Parse rgb(r, g, b) or rgba(r, g, b, a) format from d3-scale-chromatic
  const match = cssColor.match(/rgba?\((\d+),\s*(\d+),\s*(\d+)(?:,\s*([\d.]+))?\)/);
  if (match) {
    return [
      parseInt(match[1]),
      parseInt(match[2]),
      parseInt(match[3]),
      match[4] ? Math.round(parseFloat(match[4]) * 255) : alpha
    ];
  }
  return [128, 128, 128, alpha];
}

export interface MacroLayerOptions {
  tasks: TaskRender[];
  trains: Train[];
  opacity: number;
  totalDays: number;
}

export function createMacroLayers({
  tasks,
  trains,
  opacity,
  totalDays
}: MacroLayerOptions): SolidPolygonLayer[] {
  if (opacity <= 0) return [];

  // Aggregate tasks into grid cells
  const numCols = Math.ceil(totalDays / DAYS_PER_CELL);
  const numRows = trains.length;
  const cellCounts: number[][] = Array.from({ length: numRows }, () =>
    Array(numCols).fill(0)
  );

  // Count tasks per cell
  for (const task of tasks) {
    const row = task.trainIndex;
    const startCol = Math.floor(task.startDay / DAYS_PER_CELL);
    const endCol = Math.floor((task.startDay + task.duration) / DAYS_PER_CELL);
    for (let col = startCol; col <= endCol && col < numCols; col++) {
      if (col >= 0 && row >= 0 && row < numRows) {
        cellCounts[row][col]++;
      }
    }
  }

  // Find max for normalization
  let maxCount = 1;
  for (const row of cellCounts) {
    for (const count of row) {
      if (count > maxCount) maxCount = count;
    }
  }

  // Create heatmap cells
  const cells: HeatmapCell[] = [];
  for (let row = 0; row < numRows; row++) {
    for (let col = 0; col < numCols; col++) {
      const count = cellCounts[row][col];
      if (count === 0) continue;

      const x = col * CELL_WIDTH;
      const y = -row * CELL_HEIGHT; // Negative Y for downward trains
      const normalized = count / maxCount;
      const cssColor = interpolateYlOrRd(normalized);
      const color = parseColorToRGBA(cssColor, Math.round(opacity * 255));

      cells.push({
        polygon: [
          [x, y],
          [x + CELL_WIDTH, y],
          [x + CELL_WIDTH, y - CELL_HEIGHT],
          [x, y - CELL_HEIGHT],
          [x, y]
        ],
        color,
        taskCount: count
      });
    }
  }

  // Year markers (vertical lines)
  const yearMarkers: YearMarker[] = [];
  for (let day = 365; day < totalDays; day += 365) {
    const x = day * pxPerDay;
    yearMarkers.push({
      polygon: [
        [x - 1, 0],
        [x + 1, 0],
        [x + 1, -numRows * CELL_HEIGHT],
        [x - 1, -numRows * CELL_HEIGHT],
        [x - 1, 0]
      ],
      color: [100, 100, 100, Math.round(opacity * 128)]
    });
  }

  return [
    new SolidPolygonLayer<HeatmapCell>({
      id: 'macro-heatmap',
      data: cells,
      getPolygon: d => d.polygon,
      getFillColor: d => d.color,
      extruded: false,
      pickable: false
    }),
    new SolidPolygonLayer<YearMarker>({
      id: 'macro-year-markers',
      data: yearMarkers,
      getPolygon: d => d.polygon,
      getFillColor: d => d.color,
      extruded: false,
      pickable: false
    })
  ];
}
