### 3. MesoLayer - Task Blocks View (0.5x <= Zoom <= 2.0x)

**File:** `apps/canvas/src/deck/layers/MesoLayer.ts`

Multiple SolidPolygonLayer stacks for backgrounds, conflicts, focus, and task blocks with hover highlighting.

```typescript
/**
 * MesoLayer - Task blocks view for 0.5x <= zoom <= 2.0x
 * Uses multiple SolidPolygonLayer stacks for backgrounds, conflicts, focus, and task blocks
 */
import { SolidPolygonLayer } from '@deck.gl/layers';
import type { TaskRender, Train } from '../../data/types';
import { DEFAULT_VIEW_CONFIG } from '../../data/types';

const { pxPerDay, pxPerTrain } = DEFAULT_VIEW_CONFIG;
const TASK_HEIGHT = pxPerTrain - 4; // 20px with 2px padding
const TASK_PADDING = 2;

interface RowBackground {
  polygon: number[][];
  color: [number, number, number, number];
}

interface TaskPolygon {
  id: string;
  polygon: number[][];
  color: [number, number, number, number];
  task: TaskRender;
}

interface EffectPolygon {
  polygon: number[][];
  color: [number, number, number, number];
}

const COLORS = {
  blue: [59, 130, 246, 255] as [number, number, number, number],
  orange: [245, 158, 11, 255] as [number, number, number, number],
  gray: [156, 163, 175, 255] as [number, number, number, number],
};

const CONFLICT_COLOR: [number, number, number, number] = [239, 68, 68, 76]; // red @ 30% opacity
const FOCUS_COLOR: [number, number, number, number] = [139, 92, 246, 102]; // violet @ 40% opacity
const HOVER_BRIGHTEN = 1.5;

function getTaskColor(task: TaskRender, isHovered: boolean): [number, number, number, number] {
  let baseColor: [number, number, number, number];
  switch (task.color) {
    case 'blue': baseColor = [...COLORS.blue]; break;
    case 'orange': baseColor = [...COLORS.orange]; break;
    default: baseColor = [...COLORS.gray];
  }

  if (isHovered) {
    baseColor[0] = Math.min(255, Math.round(baseColor[0] * HOVER_BRIGHTEN));
    baseColor[1] = Math.min(255, Math.round(baseColor[1] * HOVER_BRIGHTEN));
    baseColor[2] = Math.min(255, Math.round(baseColor[2] * HOVER_BRIGHTEN));
  }

  return baseColor;
}

function createRectPolygon(x: number, y: number, w: number, h: number): number[][] {
  return [
    [x, y],
    [x + w, y],
    [x + w, y - h],
    [x, y - h],
    [x, y]
  ];
}

export interface MesoLayerOptions {
  tasks: TaskRender[];
  trains: Train[];
  opacity: number;
  totalDays: number;
  hoveredTaskId?: string | null;
  selectedTaskId?: string | null;
  focusedTaskId?: string | null;
  viewportBounds?: { minX: number; maxX: number; minY: number; maxY: number };
}

export function createMesoLayers({
  tasks,
  trains,
  opacity,
  totalDays,
  hoveredTaskId,
  selectedTaskId,
  focusedTaskId,
  viewportBounds
}: MesoLayerOptions): SolidPolygonLayer[] {
  if (opacity <= 0) return [];

  // Row backgrounds (alternating colors)
  const rowBackgrounds: RowBackground[] = trains.map((_, index) => ({
    polygon: createRectPolygon(0, -index * pxPerTrain, totalDays * pxPerDay, pxPerTrain),
    color: index % 2 === 0
      ? [255, 255, 255, Math.round(opacity * 255)]
      : [248, 250, 252, Math.round(opacity * 255)] // slate-50
  }));

  // Filter visible tasks if viewport bounds provided
  const visibleTasks = viewportBounds
    ? tasks.filter(task => {
        const x1 = task.startDay * pxPerDay;
        const x2 = x1 + task.duration * pxPerDay;
        const y = -task.trainIndex * pxPerTrain;
        return x2 >= viewportBounds.minX &&
               x1 <= viewportBounds.maxX &&
               y >= viewportBounds.minY &&
               y - pxPerTrain <= viewportBounds.maxY;
      })
    : tasks;

  // Conflict glows
  const conflictGlows: EffectPolygon[] = visibleTasks
    .filter(task => task.hasConflict)
    .map(task => ({
      polygon: createRectPolygon(
        task.startDay * pxPerDay - 4,
        -task.trainIndex * pxPerTrain - TASK_PADDING + 4,
        task.duration * pxPerDay + 8,
        TASK_HEIGHT + 8
      ),
      color: [CONFLICT_COLOR[0], CONFLICT_COLOR[1], CONFLICT_COLOR[2], Math.round(CONFLICT_COLOR[3] * opacity)]
    }));

  // Focus ring
  const focusRings: EffectPolygon[] = focusedTaskId
    ? visibleTasks
        .filter(task => task.id === focusedTaskId)
        .map(task => ({
          polygon: createRectPolygon(
            task.startDay * pxPerDay - 4,
            -task.trainIndex * pxPerTrain - TASK_PADDING + 4,
            task.duration * pxPerDay + 8,
            TASK_HEIGHT + 8
          ),
          color: [FOCUS_COLOR[0], FOCUS_COLOR[1], FOCUS_COLOR[2], Math.round(FOCUS_COLOR[3] * opacity)]
        }))
    : [];

  // Task blocks
  const taskPolygons: TaskPolygon[] = visibleTasks.map(task => ({
    id: task.id,
    polygon: createRectPolygon(
      task.startDay * pxPerDay,
      -task.trainIndex * pxPerTrain - TASK_PADDING,
      task.duration * pxPerDay,
      TASK_HEIGHT
    ),
    color: getTaskColor(task, task.id === hoveredTaskId),
    task
  }));

  const layers: SolidPolygonLayer[] = [];

  layers.push(
    new SolidPolygonLayer<RowBackground>({
      id: 'meso-row-backgrounds',
      data: rowBackgrounds,
      getPolygon: d => d.polygon,
      getFillColor: d => d.color,
      extruded: false,
      pickable: false
    })
  );

  if (conflictGlows.length > 0) {
    layers.push(
      new SolidPolygonLayer<EffectPolygon>({
        id: 'meso-conflict-glows',
        data: conflictGlows,
        getPolygon: d => d.polygon,
        getFillColor: d => d.color,
        extruded: false,
        pickable: false
      })
    );
  }

  if (focusRings.length > 0) {
    layers.push(
      new SolidPolygonLayer<EffectPolygon>({
        id: 'meso-focus-rings',
        data: focusRings,
        getPolygon: d => d.polygon,
        getFillColor: d => d.color,
        extruded: false,
        pickable: false
      })
    );
  }

  layers.push(
    new SolidPolygonLayer<TaskPolygon>({
      id: 'meso-task-blocks',
      data: taskPolygons,
      getPolygon: d => d.polygon,
      getFillColor: d => d.color,
      extruded: false,
      pickable: true,
      updateTriggers: {
        getFillColor: [hoveredTaskId, opacity]
      }
    })
  );

  return layers;
}
