### 4. MicroLayer - Detailed Task Cards (Zoom > 2.0x)

**File:** `apps/canvas/src/deck/layers/MicroLayer.ts`

7 layer composition: row backgrounds, grid lines, conflict glows, focus ring, task cards, text labels, and dependency arrows.

```typescript
/**
 * MicroLayer - Detailed task cards for zoom > 2.0x
 * Uses 7 layers: row backgrounds, grid lines, conflict glows, focus ring, task cards, text labels, dependency arrows
 */
import { SolidPolygonLayer, TextLayer, PathLayer } from '@deck.gl/layers';
import type { TaskRender, Train } from '../../data/types';
import { DEFAULT_VIEW_CONFIG } from '../../data/types';

const { pxPerDay, pxPerTrain } = DEFAULT_VIEW_CONFIG;
const TASK_HEIGHT = pxPerTrain - 4;
const TASK_PADDING = 2;
const MIN_LABEL_WIDTH = 40; // Minimum width to show label
const MAX_LABELS = 50; // Maximum labels to render for performance
const DAYS_PER_WEEK = 7;

interface RowBackground {
  polygon: number[][];
  color: [number, number, number, number];
}

interface GridLine {
  path: [number, number][];
  color: [number, number, number, number];
}

interface TaskCard {
  id: string;
  polygon: number[][];
  color: [number, number, number, number];
  task: TaskRender;
}

interface TaskLabel {
  id: string;
  position: [number, number];
  text: string;
  color: [number, number, number, number];
}

interface DependencyPath {
  path: [number, number][];
  color: [number, number, number, number];
}

const COLORS = {
  blue: [59, 130, 246, 255] as [number, number, number, number],
  orange: [245, 158, 11, 255] as [number, number, number, number],
  gray: [156, 163, 175, 255] as [number, number, number, number],
};

const SELECTION_COLOR: [number, number, number, number] = [6, 182, 212, 255]; // cyan-500
const CONFLICT_COLOR: [number, number, number, number] = [239, 68, 68, 76];
const FOCUS_COLOR: [number, number, number, number] = [139, 92, 246, 102];
const DEPENDENCY_COLOR: [number, number, number, number] = [100, 116, 139, 255]; // slate-500

function createRectPolygon(x: number, y: number, w: number, h: number): number[][] {
  return [[x, y], [x + w, y], [x + w, y - h], [x, y - h], [x, y]];
}

function getTaskColor(task: TaskRender, isHovered: boolean, isSelected: boolean): [number, number, number, number] {
  if (isSelected) return SELECTION_COLOR;

  let baseColor: [number, number, number, number];
  switch (task.color) {
    case 'blue': baseColor = [...COLORS.blue]; break;
    case 'orange': baseColor = [...COLORS.orange]; break;
    default: baseColor = [...COLORS.gray];
  }

  if (isHovered) {
    baseColor[0] = Math.min(255, Math.round(baseColor[0] * 1.3));
    baseColor[1] = Math.min(255, Math.round(baseColor[1] * 1.3));
    baseColor[2] = Math.min(255, Math.round(baseColor[2] * 1.3));
  }

  return baseColor;
}

function filterVisibleTasks(
  tasks: TaskRender[],
  bounds: { minX: number; maxX: number; minY: number; maxY: number },
  overscan = 200
): TaskRender[] {
  return tasks.filter(task => {
    const x1 = task.startDay * pxPerDay;
    const x2 = x1 + task.duration * pxPerDay;
    const y = -task.trainIndex * pxPerTrain;
    return x2 >= bounds.minX - overscan &&
           x1 <= bounds.maxX + overscan &&
           y >= bounds.minY - overscan &&
           y - pxPerTrain <= bounds.maxY + overscan;
  });
}

function createDependencyPath(
  from: TaskRender,
  to: TaskRender,
  allTasks: Map<string, TaskRender>
): [number, number][] {
  const fromX = (from.startDay + from.duration) * pxPerDay;
  const fromY = -from.trainIndex * pxPerTrain - pxPerTrain / 2;
  const toX = to.startDay * pxPerDay;
  const toY = -to.trainIndex * pxPerTrain - pxPerTrain / 2;

  const midX = (fromX + toX) / 2;

  if (from.trainIndex === to.trainIndex) {
    // Same row: simple curve
    return [
      [fromX, fromY],
      [midX, fromY - 10],
      [toX, toY]
    ];
  } else {
    // Different rows: S-curve
    return [
      [fromX, fromY],
      [fromX + 20, fromY],
      [toX - 20, toY],
      [toX, toY]
    ];
  }
}

export interface MicroLayerOptions {
  tasks: TaskRender[];
  trains: Train[];
  opacity: number;
  totalDays: number;
  hoveredTaskId?: string | null;
  selectedTaskId?: string | null;
  focusedTaskId?: string | null;
  viewportBounds: { minX: number; maxX: number; minY: number; maxY: number };
}

export function createMicroLayers(options: MicroLayerOptions): (SolidPolygonLayer | TextLayer | PathLayer)[] {
  const {
    tasks,
    trains,
    opacity,
    totalDays,
    hoveredTaskId,
    selectedTaskId,
    focusedTaskId,
    viewportBounds
  } = options;

  if (opacity <= 0) return [];

  const layers: (SolidPolygonLayer | TextLayer | PathLayer)[] = [];

  // 1. Row backgrounds
  const rowBackgrounds: RowBackground[] = trains.map((_, index) => ({
    polygon: createRectPolygon(0, -index * pxPerTrain, totalDays * pxPerDay, pxPerTrain),
    color: index % 2 === 0
      ? [255, 255, 255, Math.round(opacity * 255)]
      : [248, 250, 252, Math.round(opacity * 255)]
  }));

  layers.push(
    new SolidPolygonLayer<RowBackground>({
      id: 'micro-row-backgrounds',
      data: rowBackgrounds,
      getPolygon: d => d.polygon,
      getFillColor: d => d.color,
      extruded: false,
      pickable: false
    })
  );

  // 2. Grid lines (weekly)
  const gridLines: GridLine[] = [];
  for (let day = DAYS_PER_WEEK; day < totalDays; day += DAYS_PER_WEEK) {
    if (day * pxPerDay < viewportBounds.minX - 100 || day * pxPerDay > viewportBounds.maxX + 100) continue;
    gridLines.push({
      path: [[day * pxPerDay, 0], [day * pxPerDay, -trains.length * pxPerTrain]],
      color: [226, 232, 240, Math.round(opacity * 255)] // slate-200
    });
  }

  layers.push(
    new PathLayer<GridLine>({
      id: 'micro-grid-lines',
      data: gridLines,
      getPath: d => d.path,
      getColor: d => d.color,
      getWidth: 1,
      widthUnits: 'pixels'
    })
  );

  // Filter visible tasks
  const visibleTasks = filterVisibleTasks(tasks, viewportBounds);
  const taskMap = new Map(tasks.map(t => [t.id, t]));

  // 3. Conflict glows
  const conflictTasks = visibleTasks.filter(t => t.hasConflict);
  if (conflictTasks.length > 0) {
    layers.push(
      new SolidPolygonLayer({
        id: 'micro-conflict-glows',
        data: conflictTasks.map(task => ({
          polygon: createRectPolygon(
            task.startDay * pxPerDay - 4,
            -task.trainIndex * pxPerTrain - TASK_PADDING + 4,
            task.duration * pxPerDay + 8,
            TASK_HEIGHT + 8
          ),
          color: [CONFLICT_COLOR[0], CONFLICT_COLOR[1], CONFLICT_COLOR[2], Math.round(CONFLICT_COLOR[3] * opacity)]
        })),
        getPolygon: d => d.polygon,
        getFillColor: d => d.color,
        extruded: false,
        pickable: false
      })
    );
  }

  // 4. Focus ring
  if (focusedTaskId) {
    const focusedTask = taskMap.get(focusedTaskId);
    if (focusedTask) {
      layers.push(
        new SolidPolygonLayer({
          id: 'micro-focus-ring',
          data: [{
            polygon: createRectPolygon(
              focusedTask.startDay * pxPerDay - 4,
              -focusedTask.trainIndex * pxPerTrain - TASK_PADDING + 4,
              focusedTask.duration * pxPerDay + 8,
              TASK_HEIGHT + 8
            ),
            color: [FOCUS_COLOR[0], FOCUS_COLOR[1], FOCUS_COLOR[2], Math.round(FOCUS_COLOR[3] * opacity)]
          }],
          getPolygon: d => d.polygon,
          getFillColor: d => d.color,
          extruded: false,
          pickable: false
        })
      );
    }
  }

  // 5. Task cards
  const taskCards: TaskCard[] = visibleTasks.map(task => ({
    id: task.id,
    polygon: createRectPolygon(
      task.startDay * pxPerDay,
      -task.trainIndex * pxPerTrain - TASK_PADDING,
      task.duration * pxPerDay,
      TASK_HEIGHT
    ),
    color: getTaskColor(task, task.id === hoveredTaskId, task.id === selectedTaskId),
    task
  }));

  layers.push(
    new SolidPolygonLayer<TaskCard>({
      id: 'micro-task-cards',
      data: taskCards,
      getPolygon: d => d.polygon,
      getFillColor: d => d.color,
      extruded: false,
      pickable: true,
      updateTriggers: {
        getFillColor: [hoveredTaskId, selectedTaskId, opacity]
      }
    })
  );

  // 6. Text labels (prioritized by width, max 50)
  const labelableTasks = visibleTasks
    .map(task => ({ task, width: task.duration * pxPerDay }))
    .filter(t => t.width >= MIN_LABEL_WIDTH)
    .sort((a, b) => b.width - a.width)
    .slice(0, MAX_LABELS);

  const taskLabels: TaskLabel[] = labelableTasks.map(({ task }) => ({
    id: task.id,
    position: [
      task.startDay * pxPerDay + task.duration * pxPerDay / 2,
      -task.trainIndex * pxPerTrain - pxPerTrain / 2
    ] as [number, number],
    text: task.type.charAt(0).toUpperCase() + task.type.slice(1),
    color: [255, 255, 255, Math.round(opacity * 255)] as [number, number, number, number]
  }));

  if (taskLabels.length > 0) {
    layers.push(
      new TextLayer<TaskLabel>({
        id: 'micro-task-labels',
        data: taskLabels,
        getPosition: d => d.position,
        getText: d => d.text,
        getColor: d => d.color,
        getSize: 11,
        getTextAnchor: 'middle',
        getAlignmentBaseline: 'center',
        fontFamily: 'system-ui, -apple-system, sans-serif',
        fontWeight: 500,
        updateTriggers: {
          getColor: [opacity]
        }
      })
    );
  }

  // 7. Dependency arrows
  const dependencyPaths: DependencyPath[] = [];
  for (const task of visibleTasks) {
    if (task.predecessorId) {
      const predecessor = taskMap.get(task.predecessorId);
      if (predecessor) {
        dependencyPaths.push({
          path: createDependencyPath(predecessor, task, taskMap),
          color: [DEPENDENCY_COLOR[0], DEPENDENCY_COLOR[1], DEPENDENCY_COLOR[2], Math.round(DEPENDENCY_COLOR[3] * opacity)]
        });
      }
    }
  }

  if (dependencyPaths.length > 0) {
    layers.push(
      new PathLayer<DependencyPath>({
        id: 'micro-dependency-arrows',
        data: dependencyPaths,
        getPath: d => d.path,
        getColor: d => d.color,
        getWidth: 2,
        widthUnits: 'pixels',
        capRounded: true,
        jointRounded: true
      })
    );
  }

  return layers;
}
