### 5. DeckCanvas - LOD Orchestrator

**File:** `apps/canvas/src/deck/DeckCanvas.tsx`

Main deck.gl canvas with OrthographicView, LOD system with hysteresis crossfades, and RBush spatial indexing.

```typescript
/**
 * DeckCanvas - deck.gl-based canvas for semantic zoom visualization
 * DECK-MIGRATE-001: Foundation component with OrthographicView
 */
import { useState, useCallback, useEffect, useRef, useMemo } from 'react';
import DeckGL from '@deck.gl/react';
import { OrthographicView, OrthographicViewState } from '@deck.gl/core';
import type { TaskRender, Train } from '../data/types';
import { DEFAULT_VIEW_CONFIG, LODLevel } from '../data/types';
import { useCanvasSelector, canvasStore, canvasActions } from '../state';
import { createMacroLayers } from './layers/MacroLayer';
import { createMesoLayers } from './layers/MesoLayer';
import { createMicroLayers } from './layers/MicroLayer';
import RBush from 'rbush';

interface DeckViewState extends OrthographicViewState {
  target: [number, number];
  zoom: number;
  minZoom: number;
  maxZoom: number;
}

export interface ViewportInfo {
  startDay: number;
  endDay: number;
  centerDay: number;
  visibleDays: number;
  firstVisibleTrain: number;
  lastVisibleTrain: number;
  visibleTrains: number;
}

export interface NavigationTarget {
  type: 'task' | 'train' | 'date';
  id?: string;
  trainIndex?: number;
  day?: number;
}

export interface DeckCanvasProps {
  zoom: number;
  lod: LODLevel;
  onZoomChange: (zoom: number) => void;
  onViewportChange?: (viewport: ViewportInfo) => void;
  onMinZoomChange?: (minZoom: number) => void;
  animatedZoomTarget?: number | null;
  onAnimatedZoomComplete?: () => void;
  navigationTarget?: NavigationTarget | null;
  onNavigationComplete?: () => void;
  perfVisible?: boolean;
  perfEvent?: string;
}

const { pxPerDay, pxPerTrain, lodThresholds } = DEFAULT_VIEW_CONFIG;

// Zoom conversion functions (deck.gl uses log2 scale)
function linearToDeckZoom(linearZoom: number): number {
  return Math.log2(linearZoom);
}

function deckToLinearZoom(deckZoom: number): number {
  return Math.pow(2, deckZoom);
}

// LOD opacity calculation with hysteresis
function calculateLODOpacities(zoom: number): { macro: number; meso: number; micro: number } {
  const HYSTERESIS = 0.15; // 15% overlap zone

  const macroThreshold = lodThresholds.macro;
  const microThreshold = lodThresholds.micro;

  let macro = 0, meso = 0, micro = 0;

  if (zoom < macroThreshold * (1 - HYSTERESIS)) {
    macro = 1;
  } else if (zoom < macroThreshold * (1 + HYSTERESIS)) {
    const t = (zoom - macroThreshold * (1 - HYSTERESIS)) / (macroThreshold * 2 * HYSTERESIS);
    macro = 1 - smoothstep(t);
    meso = smoothstep(t);
  } else if (zoom < microThreshold * (1 - HYSTERESIS)) {
    meso = 1;
  } else if (zoom < microThreshold * (1 + HYSTERESIS)) {
    const t = (zoom - microThreshold * (1 - HYSTERESIS)) / (microThreshold * 2 * HYSTERESIS);
    meso = 1 - smoothstep(t);
    micro = smoothstep(t);
  } else {
    micro = 1;
  }

  return { macro, meso, micro };
}

function smoothstep(t: number): number {
  t = Math.max(0, Math.min(1, t));
  return t * t * (3 - 2 * t);
}

// Spatial index for viewport culling
interface TaskBBox {
  minX: number;
  minY: number;
  maxX: number;
  maxY: number;
  task: TaskRender;
}

function createSpatialIndex(tasks: TaskRender[]): RBush<TaskBBox> {
  const tree = new RBush<TaskBBox>();
  const items = tasks.map(task => ({
    minX: task.startDay * pxPerDay,
    minY: -task.trainIndex * pxPerTrain - pxPerTrain,
    maxX: (task.startDay + task.duration) * pxPerDay,
    maxY: -task.trainIndex * pxPerTrain,
    task
  }));
  tree.load(items);
  return tree;
}

export function DeckCanvas({
  zoom,
  lod: _lod,
  onZoomChange,
  onViewportChange,
  onMinZoomChange,
  animatedZoomTarget,
  onAnimatedZoomComplete,
  navigationTarget,
  onNavigationComplete,
  perfVisible: _perfVisible,
  perfEvent: _perfEvent,
}: DeckCanvasProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const [containerSize, setContainerSize] = useState({ width: 800, height: 600 });

  // Get data from state
  const { tasks, meta } = canvasStore.getState().data ?? { tasks: [], trains: [], meta: { totalDays: 3650, startDate: '2024-01-01' } };
  const trains = useMemo(() =>
    Array.from({ length: 50 }, (_, i) => ({ id: `TRAIN-${String(i + 1).padStart(3, '0')}`, name: `Train ${i + 1}` })),
    []
  );

  // Interaction state
  const hoveredTaskId = useCanvasSelector(s => s.interaction.hoveredTaskId);
  const selectedTaskId = useCanvasSelector(s => s.interaction.selectedTaskId);
  const focusedTaskId = useCanvasSelector(s => s.interaction.focusedTaskId);

  // Create spatial index
  const spatialIndex = useMemo(() => createSpatialIndex(tasks), [tasks]);

  // View state
  const [viewState, setViewState] = useState<DeckViewState>(() => ({
    target: [meta.totalDays * pxPerDay / 2, -trains.length * pxPerTrain / 2],
    zoom: linearToDeckZoom(zoom),
    minZoom: linearToDeckZoom(0.1),
    maxZoom: linearToDeckZoom(5)
  }));

  // Handle container resize
  useEffect(() => {
    if (!containerRef.current) return;

    const observer = new ResizeObserver(entries => {
      const entry = entries[0];
      if (entry) {
        setContainerSize({
          width: entry.contentRect.width,
          height: entry.contentRect.height
        });
      }
    });

    observer.observe(containerRef.current);
    return () => observer.disconnect();
  }, []);

  // Calculate viewport bounds
  const viewportBounds = useMemo(() => {
    const linearZ = deckToLinearZoom(viewState.zoom);
    const halfW = containerSize.width / 2 / linearZ;
    const halfH = containerSize.height / 2 / linearZ;
    return {
      minX: viewState.target[0] - halfW,
      maxX: viewState.target[0] + halfW,
      minY: viewState.target[1] - halfH,
      maxY: viewState.target[1] + halfH
    };
  }, [viewState, containerSize]);

  // Calculate LOD opacities
  const lodOpacities = useMemo(
    () => calculateLODOpacities(deckToLinearZoom(viewState.zoom)),
    [viewState.zoom]
  );

  // Create layers based on LOD
  const layers = useMemo(() => {
    const totalDays = meta.totalDays;
    const allLayers: any[] = [];

    if (lodOpacities.macro > 0) {
      allLayers.push(...createMacroLayers({
        tasks,
        trains,
        opacity: lodOpacities.macro,
        totalDays
      }));
    }

    if (lodOpacities.meso > 0) {
      allLayers.push(...createMesoLayers({
        tasks,
        trains,
        opacity: lodOpacities.meso,
        totalDays,
        hoveredTaskId,
        selectedTaskId,
        focusedTaskId,
        viewportBounds
      }));
    }

    if (lodOpacities.micro > 0) {
      allLayers.push(...createMicroLayers({
        tasks,
        trains,
        opacity: lodOpacities.micro,
        totalDays,
        hoveredTaskId,
        selectedTaskId,
        focusedTaskId,
        viewportBounds
      }));
    }

    return allLayers;
  }, [tasks, trains, lodOpacities, hoveredTaskId, selectedTaskId, focusedTaskId, viewportBounds]);

  // Handle view state change
  const handleViewStateChange = useCallback(({ viewState: newViewState }: { viewState: DeckViewState }) => {
    setViewState(newViewState);
    const linearZoom = deckToLinearZoom(newViewState.zoom);
    onZoomChange(linearZoom);

    // Update viewport info
    if (onViewportChange) {
      const z = linearZoom;
      const halfW = containerSize.width / 2 / z;
      const startDay = Math.max(0, (newViewState.target[0] - halfW) / pxPerDay);
      const endDay = Math.min(meta.totalDays, (newViewState.target[0] + halfW) / pxPerDay);

      onViewportChange({
        startDay,
        endDay,
        centerDay: (startDay + endDay) / 2,
        visibleDays: endDay - startDay,
        firstVisibleTrain: 0,
        lastVisibleTrain: trains.length - 1,
        visibleTrains: trains.length
      });
    }
  }, [onZoomChange, onViewportChange, containerSize, meta.totalDays, trains.length]);

  // Handle hover
  const handleHover = useCallback((info: any) => {
    if (info.object?.task) {
      canvasStore.dispatch(canvasActions.interaction.setHoveredTask(info.object.task.id));
    } else {
      canvasStore.dispatch(canvasActions.interaction.clearHover(null));
    }
  }, []);

  // Handle click
  const handleClick = useCallback((info: any) => {
    if (info.object?.task) {
      canvasStore.dispatch(canvasActions.interaction.setSelectedTask(info.object.task.id));
    } else {
      canvasStore.dispatch(canvasActions.interaction.clearSelection(null));
    }
  }, []);

  // OrthographicView for timeline
  const views = new OrthographicView({
    id: 'timeline',
    flipY: false,
    controller: {
      scrollZoom: true,
      dragPan: true,
      doubleClickZoom: true,
      touchRotate: false,
      keyboard: true
    }
  });

  return (
    <div
      ref={containerRef}
      style={{ width: '100%', height: '100%', position: 'relative', background: '#f4f4f5' }}
    >
      <DeckGL
        views={views}
        viewState={viewState}
        onViewStateChange={handleViewStateChange as any}
        controller={true}
        layers={layers}
        onHover={handleHover}
        onClick={handleClick}
        width="100%"
        height="100%"
      />

      {/* LOD indicator */}
      <div
        style={{
          position: 'absolute',
          top: '8px',
          right: '8px',
          padding: '4px 8px',
          background: 'rgba(0,0,0,0.7)',
          color: 'white',
          fontSize: '12px',
          borderRadius: '4px'
        }}
      >
        {lodOpacities.macro > 0.5 ? 'MACRO' : lodOpacities.micro > 0.5 ? 'MICRO' : 'MESO'}
        {' | '}
        {deckToLinearZoom(viewState.zoom).toFixed(2)}x
      </div>
    </div>
  );
}
