/**
 * Data types for MMS Canvas
 * Two-layer architecture: Persistent (JSON-serializable) and Rendering (computed)
 */

export type TaskType = 'maintenance' | 'overhaul' | 'inspection';
export type TaskColor = 'blue' | 'orange' | 'gray';
export type AssetType = 'train' | 'tram';
export type LODLevel = 'macro' | 'meso' | 'micro';

/**
 * Persistent Task - serializable to JSON
 */
export interface Task {
  id: string;
  trainId: string;
  startDate: string; // ISO 8601: "2024-03-15"
  endDate: string;
  type: TaskType;
  hasConflict: boolean;
  predecessorId?: string; // For dependency lines
}

/**
 * Rendering Task - computed at load, used by canvas
 */
export interface TaskRender {
  id: string;
  trainIndex: number; // Y position (0-based)
  startDay: number; // X position (days since meta.startDate)
  duration: number; // Width in days
  color: TaskColor;
  hasConflict: boolean;
  type: TaskType;
  predecessorId?: string;
}

/**
 * Train (row) definition
 */
export interface Train {
  id: string;
  name: string;
}

/**
 * Data metadata
 */
export interface DataMeta {
  startDate: string; // ISO 8601
  totalDays: number;
}

/**
 * Complete render data package
 */
export interface RenderData {
  tasks: TaskRender[];
  trains: Train[];
  meta: DataMeta;
}

/**
 * Default view configuration constants
 */
export const DEFAULT_VIEW_CONFIG = {
  pxPerDay: 10, // Pixels per day (X scale)
  pxPerTrain: 24, // Pixels per train row (Y scale)
  minZoom: 0.1,
  maxZoom: 5,
  lodThresholds: {
    macro: 0.5, // Below this = heatmap
    micro: 2.0 // Above this = detailed cards
  }
} as const;
