/**
 * Viewport Slice - Camera position, zoom, momentum, and animation
 */
import { createSyncSlice } from '@mms/toolkit';

export interface CameraPosition {
  x: number;
  y: number;
}

export interface ViewportSliceState {
  camera: CameraPosition & { zoom: number };
  momentum: { vx: number; vy: number };
  isAnimating: boolean;
  animationTarget: { x?: number; y?: number; zoom?: number } | null;
}

const initialState: ViewportSliceState = {
  camera: { x: 0, y: 0, zoom: 1 },
  momentum: { vx: 0, vy: 0 },
  isAnimating: false,
  animationTarget: null
};

export const viewportSlice = createSyncSlice({
  name: 'viewport',
  initialState,
  reducers: {
    setCamera: (state, payload: Partial<CameraPosition & { zoom: number }>) => {
      if (payload.x !== undefined) state.camera.x = payload.x;
      if (payload.y !== undefined) state.camera.y = payload.y;
      if (payload.zoom !== undefined) state.camera.zoom = payload.zoom;
    },
    setZoom: (state, payload: number) => {
      state.camera.zoom = payload;
    },
    setMomentum: (state, payload: { vx: number; vy: number }) => {
      state.momentum = payload;
    },
    startAnimation: (state, payload: { x?: number; y?: number; zoom?: number }) => {
      state.isAnimating = true;
      state.animationTarget = payload;
    },
    stopAnimation: (state) => {
      state.isAnimating = false;
      state.animationTarget = null;
    }
  }
});
