```typescript
/**
 * Mock Data Generator
 * Pre-generates deterministic data: 50 trains x 10 years
 * Uses seeded random for reproducible results
 */
import type { TaskRender, Train, RenderData, DataMeta, TaskType, TaskColor } from './types';

// Seeded random number generator
function createSeededRandom(seed: number) {
  let s = seed;
  return () => {
    s = (s * 1103515245 + 12345) & 0x7fffffff;
    return s / 0x7fffffff;
  };
}

const TASK_TYPES: TaskType[] = ['maintenance', 'overhaul', 'inspection'];
const TYPE_WEIGHTS = [0.6, 0.25, 0.15]; // 60% maintenance, 25% overhaul, 15% inspection
const TYPE_COLORS: Record<TaskType, TaskColor> = {
  maintenance: 'blue',
  overhaul: 'orange',
  inspection: 'gray'
};

function selectType(rand: () => number): TaskType {
  const r = rand();
  let cumulative = 0;
  for (let i = 0; i < TASK_TYPES.length; i++) {
    cumulative += TYPE_WEIGHTS[i];
    if (r < cumulative) return TASK_TYPES[i];
  }
  return TASK_TYPES[0];
}

export function generateRenderData(seed = 42): RenderData {
  const rand = createSeededRandom(seed);

  const NUM_TRAINS = 50;
  const TOTAL_DAYS = 3650; // 10 years
  const TASKS_PER_TRAIN_PER_YEAR = 4; // ~4 tasks per train per year

  const trains: Train[] = Array.from({ length: NUM_TRAINS }, (_, i) => ({
    id: `TRAIN-${String(i + 1).padStart(3, '0')}`,
    name: `Train ${i + 1}`
  }));

  const tasks: TaskRender[] = [];
  let taskId = 1;

  for (let trainIndex = 0; trainIndex < NUM_TRAINS; trainIndex++) {
    const numTasks = Math.round(TASKS_PER_TRAIN_PER_YEAR * 10 * (0.8 + rand() * 0.4));

    for (let t = 0; t < numTasks; t++) {
      const type = selectType(rand);
      const startDay = Math.floor(rand() * (TOTAL_DAYS - 30));
      const duration = Math.floor(5 + rand() * 25); // 5-30 days
      const hasConflict = rand() < 0.15; // 15% chance
      const hasPredecessor = rand() < 0.3; // 30% chance

      tasks.push({
        id: `TASK-${String(taskId++).padStart(5, '0')}`,
        trainIndex,
        startDay,
        duration,
        type,
        color: TYPE_COLORS[type],
        hasConflict,
        predecessorId: hasPredecessor && taskId > 2
          ? `TASK-${String(Math.floor(rand() * (taskId - 1)) + 1).padStart(5, '0')}`
          : undefined
      });
    }
  }

  const meta: DataMeta = {
    startDate: '2024-01-01',
    totalDays: TOTAL_DAYS
  };

  return { tasks, trains, meta };
}

// Cached render data
let cachedData: RenderData | null = null;

export function getRenderData(): RenderData {
  if (!cachedData) {
    cachedData = generateRenderData();
  }
  return cachedData;
}
