/**
 * Performance Monitor - Pure React implementation (no r3f-perf dependency)
 * Provides FPS display and performance event tracking
 */
import { useEffect, useCallback, useState, useRef } from 'react';

export type PerfEvent = 'idle' | 'panning' | 'zooming' | 'animating' | 'lod_transition' | 'unknown';

export function usePerfMonitorToggle(initialVisible = false) {
  const [visible, setVisible] = useState(initialVisible);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'p' && !e.ctrlKey && !e.metaKey && !e.altKey &&
          !(e.target instanceof HTMLInputElement) &&
          !(e.target instanceof HTMLTextAreaElement)) {
        setVisible((v) => !v);
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, []);

  const toggle = useCallback(() => setVisible((v) => !v), []);
  return { visible, toggle, setVisible };
}

interface FPSStats {
  fps: number;
  avg: number;
  min: number;
  frameTime: number;
}

export function useFPSMonitor(): FPSStats {
  const [stats, setStats] = useState<FPSStats>({ fps: 60, avg: 60, min: 60, frameTime: 16.67 });
  const frameTimesRef = useRef<number[]>([]);
  const lastTimeRef = useRef(performance.now());

  useEffect(() => {
    let animationId: number;

    const measure = () => {
      const now = performance.now();
      const delta = now - lastTimeRef.current;
      lastTimeRef.current = now;

      frameTimesRef.current.push(delta);
      if (frameTimesRef.current.length > 60) {
        frameTimesRef.current.shift();
      }

      const times = frameTimesRef.current;
      const avgTime = times.reduce((a, b) => a + b, 0) / times.length;
      const maxTime = Math.max(...times);

      setStats({
        fps: Math.round(1000 / delta),
        avg: Math.round(1000 / avgTime),
        min: Math.round(1000 / maxTime),
        frameTime: Math.round(avgTime * 100) / 100
      });

      animationId = requestAnimationFrame(measure);
    };

    animationId = requestAnimationFrame(measure);
    return () => cancelAnimationFrame(animationId);
  }, []);

  return stats;
}

interface PerfMonitorProps {
  visible?: boolean;
  event?: PerfEvent;
}

export function PerfMonitor({ visible = true, event = 'idle' }: PerfMonitorProps) {
  const stats = useFPSMonitor();

  if (!visible) return null;

  const fpsColor = stats.fps >= 55 ? '#22c55e' : stats.fps >= 30 ? '#eab308' : '#ef4444';

  return (
    <div
      style={{
        position: 'absolute',
        top: 8,
        left: 8,
        padding: '8px 12px',
        background: 'rgba(0, 0, 0, 0.75)',
        color: 'white',
        fontFamily: 'monospace',
        fontSize: '12px',
        borderRadius: '4px',
        lineHeight: 1.4,
        minWidth: '120px'
      }}
    >
      <div style={{ color: fpsColor, fontWeight: 'bold' }}>
        FPS: {stats.fps}
      </div>
      <div>Avg: {stats.avg}</div>
      <div>Min: {stats.min}</div>
      <div>Frame: {stats.frameTime}ms</div>
      <div style={{ marginTop: 4, color: '#94a3b8', textTransform: 'uppercase', fontSize: '10px' }}>
        {event}
      </div>
    </div>
  );
}
